                    .map(c => ({ ...c, percentage: total > 0 ? (c.amount / total) * 100 : 0 }))
                    .sort((a, b) => b.amount - a.amount);

            setMonthlyData({ 
                totalIncome: tIncome, 
                totalExpense: tExpense, 
                incomeCategories: process(incMap, tIncome), 
                expenseCategories: process(expMap, tExpense) 
            });
            setLoading(false);
        };
        fetchMonthlyData();
    }, [year, month]);

