                                    <Icon className="w-5 h-5" />
                                </div>
                                <span className={`text-[10px] font-bold truncate w-full text-center ${isSelected ? 'text-white' : 'text-slate-400'}`}>{cat.name}</span>
                            </button>
                        );
                    })}
