import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { supabase } from '../lib/supabase';
import { Account, Transaction } from '../types';
import { useToast } from './Toast';
import ConfirmDialog from './ConfirmDialog';
import { 
    EllipsisVerticalIcon, PlusIcon, XMarkIcon, WalletIcon, 
    ArrowUpIcon, ArrowDownIcon, ArrowsRightLeftIcon,
    CalendarDaysIcon, PencilSquareIcon, TrashIcon, CheckCircleIcon, InformationCircleIcon,
    PaintBrushIcon, LandmarkIcon, BanknoteIcon, BriefcaseIcon, ChevronLeftIcon
} from './icons';
import { logActivity } from '../lib/logger';

const formatCurrency = (amount: number, currency: string = 'د.ل') => {
    return new Intl.NumberFormat('ar-LY', { style: 'currency', currency: 'LYD', minimumFractionDigits: 0 }).format(amount).replace('LYD', currency);
};

const THEME_OPTIONS = [
    { id: 'blue', name: 'أزرق احترافي', class: 'bg-gradient-to-br from-blue-600 to-blue-800 border-blue-400/30', preview: 'bg-blue-600' },
    { id: 'emerald', name: 'زمردي', class: 'bg-gradient-to-br from-emerald-500 to-teal-700 border-emerald-400/30', preview: 'bg-emerald-500' },
    { id: 'purple', name: 'بنفسجي ملكي', class: 'bg-gradient-to-br from-indigo-600 to-purple-800 border-purple-400/30', preview: 'bg-purple-600' },
    { id: 'rose', name: 'وردي داكن', class: 'bg-gradient-to-br from-rose-500 to-pink-700 border-rose-400/30', preview: 'bg-rose-500' },
    { id: 'amber', name: 'ذهبي دافئ', class: 'bg-gradient-to-br from-amber-500 to-orange-700 border-amber-400/30', preview: 'bg-amber-500' },
    { id: 'dark', name: 'أسود فحمي', class: 'bg-gradient-to-br from-slate-800 to-slate-950 border-slate-700/30', preview: 'bg-slate-800' },
];

const getDefaultThemeForType = (type: string) => {
    switch (type) {
        case 'بنكي': return 'blue';
        case 'نقدي': return 'emerald';
        case 'مخصص': return 'purple';
        default: return 'dark';
    }
};

const getAccountTypeIcon = (type: string) => {
    switch (type) {
        case 'بنكي': return LandmarkIcon;
        case 'نقدي': return BanknoteIcon;
        case 'مخصص': return BriefcaseIcon;
        default: return WalletIcon;
    }
};

const AccountDetailsModal: React.FC<{
    account: Account;
    onClose: () => void;
    onEdit: () => void;
    onDelete: () => void;
}> = ({ account, onClose, onEdit, onDelete }) => {
    const [transactions, setTransactions] = useState<Transaction[]>([]);
    const [loading, setLoading] = useState(true);
    const [stats, setStats] = useState({ income: 0, expense: 0 });

    useEffect(() => {
        const fetchData = async () => {
            setLoading(true);
            const { data: txs } = await supabase
                .from('transactions')
                .select('*, categories(name, icon, color), accounts:account_id(name), to_accounts:to_account_id(name)')
                .or(`account_id.eq.${account.id},to_account_id.eq.${account.id}`)
                .order('date', { ascending: false })
                .limit(15);

            if (txs) {
                setTransactions(txs as unknown as Transaction[]);
                let inc = 0, exp = 0;
                txs.forEach((t: any) => {
                    if (t.type === 'income' && t.account_id === account.id) inc += t.amount;
                    if (t.type === 'expense' && t.account_id === account.id) exp += t.amount;
                });
                setStats({ income: inc, expense: exp });
            }
            setLoading(false);
        };
        fetchData();
    }, [account.id]);

    const themeId = account.theme || getDefaultThemeForType(account.type);
    const theme = THEME_OPTIONS.find(t => t.id === themeId) || THEME_OPTIONS[0];

    return (
        <div className="fixed inset-0 z-[100] bg-slate-950/90 backdrop-blur-xl flex items-center justify-center p-4 animate-fade-in pt-safe pb-safe">
            <div className="relative w-full max-w-2xl bg-slate-900 rounded-[2.5rem] shadow-2xl border border-white/10 flex flex-col max-h-[90vh] overflow-hidden animate-slide-up">
                <div className={`shrink-0 p-8 ${theme.class} relative overflow-hidden`}>
                    <div className="absolute inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-20 pointer-events-none"></div>
                    <div className="relative z-10 flex justify-between items-start text-white">
                        <div>
                            <p className="text-[10px] font-black uppercase tracking-[0.2em] opacity-60 mb-2">تفاصيل الحساب</p>
                            <h2 className="text-3xl font-black">{account.name}</h2>
                            <p className="text-sm font-bold opacity-80 mt-1">{account.type}</p>
                        </div>
                        <button onClick={onClose} className="p-3 rounded-full bg-white/10 border border-white/10 hover:bg-white/20 transition-all">
                            <XMarkIcon className="w-6 h-6" />
                        </button>
                    </div>
                    <div className="relative z-10 mt-8 flex flex-col items-center">
                        <p className="text-[10px] font-bold text-white/50 mb-1">الرصيد المتاح حالياً</p>
                        <h3 className="text-5xl font-black text-white">{formatCurrency(account.balance, account.currency)}</h3>
                    </div>
                    <div className="relative z-10 mt-8 grid grid-cols-2 gap-4">
                        <div className="bg-black/20 backdrop-blur-md p-4 rounded-2xl border border-white/5">
                            <p className="text-[9px] font-black text-emerald-400 uppercase mb-1">إجمالي الوارد</p>
                            <p className="text-lg font-bold text-white">+{formatCurrency(stats.income)}</p>
                        </div>
                        <div className="bg-black/20 backdrop-blur-md p-4 rounded-2xl border border-white/5">
                            <p className="text-[9px] font-black text-rose-400 uppercase mb-1">إجمالي الصادر</p>
                            <p className="text-lg font-bold text-white">-{formatCurrency(stats.expense)}</p>
                        </div>
                    </div>
                </div>

                <div className="flex-1 overflow-y-auto custom-scrollbar p-6 bg-slate-900">
                    <div className="flex justify-between items-center mb-6">
                        <h4 className="font-black text-slate-400 text-xs uppercase tracking-widest">السجل الأخير</h4>
                        <div className="flex gap-2">
                             <button onClick={onEdit} className="p-2 rounded-xl bg-slate-800 text-cyan-400 border border-white/5 hover:bg-slate-700 transition-all"><PencilSquareIcon className="w-5 h-5"/></button>
                             <button onClick={onDelete} className="p-2 rounded-xl bg-slate-800 text-rose-400 border border-white/5 hover:bg-slate-700 transition-all"><TrashIcon className="w-5 h-5"/></button>
                        </div>
                    </div>

                    {loading ? (
                        <div className="space-y-3">{[1,2,3].map(i => <div key={i} className="h-16 bg-slate-800/50 rounded-2xl animate-pulse"></div>)}</div>
                    ) : transactions.length === 0 ? (
                        <div className="text-center py-10 opacity-30 font-bold text-sm">لا توجد معاملات مسجلة</div>
                    ) : (
                        <div className="space-y-2">
                            {transactions.map(tx => {
                                const isIncome = tx.type === 'income' || (tx.type === 'transfer' && tx.to_account_id === account.id);
                                return (
                                    <div key={tx.id} className="flex items-center justify-between p-4 bg-slate-800/40 rounded-2xl border border-white/5">
                                        <div className="flex items-center gap-3">
                                            <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${isIncome ? 'bg-emerald-500/10 text-emerald-400' : 'bg-rose-500/10 text-rose-400'}`}>
                                                {tx.type === 'transfer' ? <ArrowsRightLeftIcon className="w-5 h-5"/> : isIncome ? <ArrowDownIcon className="w-5 h-5"/> : <ArrowUpIcon className="w-5 h-5"/>}
                                            </div>
                                            <div>
                                                <p className="text-xs font-bold text-white line-clamp-1">{tx.notes || tx.categories?.name || 'معاملة'}</p>
                                                <p className="text-[10px] text-slate-500">{new Date(tx.date).toLocaleDateString('ar-LY')}</p>
                                            </div>
                                        </div>
                                        <span className={`text-sm font-black ${isIncome ? 'text-emerald-400' : 'text-rose-400'}`}>{isIncome ? '+' : '-'}{formatCurrency(tx.amount)}</span>
                                    </div>
                                );
                            })}
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

const AccountForm: React.FC<{ account?: Account | null; onSave: () => void; onCancel: () => void; }> = ({ account, onSave, onCancel }) => {
    const toast = useToast();
    const [name, setName] = useState(account?.name || '');
    const [type, setType] = useState(account?.type || 'بنكي');
    const [balance, setBalance] = useState(account?.balance?.toString() || '0');
    const [theme, setTheme] = useState(account?.theme || 'blue');
    const [isSaving, setIsSaving] = useState(false);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsSaving(true);
        const data = { name, type, balance: parseFloat(balance), theme };
        const { error } = account?.id 
            ? await supabase.from('accounts').update(data).eq('id', account.id) 
            : await supabase.from('accounts').insert(data);

        if (error) toast.error('فشل في حفظ البيانات');
        else {
            logActivity(`${account?.id ? 'تعديل' : 'إضافة'} حساب: ${name}`);
            onSave();
        }
        setIsSaving(false);
    };

    return (
        <form onSubmit={handleSubmit} className="space-y-6">
            <div>
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-2 block">اسم الحساب</label>
                <input type="text" value={name} onChange={e => setName(e.target.value)} required className="w-full bg-slate-800 border border-white/5 rounded-2xl p-4 text-white focus:outline-none focus:border-cyan-500 transition-all" placeholder="مثلاً: المحفظة الشخصية، حساب الراتب..." />
            </div>
            <div className="grid grid-cols-2 gap-4">
                <div>
                    <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-2 block">نوع الحساب</label>
                    <select value={type} onChange={e => setType(e.target.value)} className="w-full bg-slate-800 border border-white/5 rounded-2xl p-4 text-white focus:outline-none">
                        <option value="بنكي">بنكي</option>
                        <option value="نقدي">نقدي</option>
                        <option value="مخصص">مخصص</option>
                    </select>
                </div>
                <div>
                    <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-2 block">الرصيد</label>
                    <input type="number" step="0.01" value={balance} onChange={e => setBalance(e.target.value)} required className="w-full bg-slate-800 border border-white/5 rounded-2xl p-4 text-white focus:outline-none" />
                </div>
            </div>
            <div>
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-3 block">لون البطاقة</label>
                <div className="grid grid-cols-3 gap-2">
                    {THEME_OPTIONS.map(opt => (
                        <button key={opt.id} type="button" onClick={() => setTheme(opt.id)} className={`h-12 rounded-xl border-2 transition-all flex items-center justify-center ${theme === opt.id ? 'border-white scale-105 shadow-xl' : 'border-transparent opacity-60'} ${opt.preview}`}>
                            {theme === opt.id && <CheckCircleIcon className="w-5 h-5 text-white" />}
                        </button>
                    ))}
                </div>
            </div>
            <button type="submit" disabled={isSaving} className="w-full py-4 bg-gradient-to-r from-cyan-600 to-blue-600 text-white rounded-2xl font-black shadow-xl active:scale-95 transition-all flex items-center justify-center gap-3">
                {isSaving ? <div className="w-6 h-6 border-4 border-white/30 border-t-white rounded-full animate-spin"></div> : 'تأكيد الحفظ'}
            </button>
        </form>
    );
};

const AccountsPage: React.FC<{ refreshTrigger: number, handleDatabaseChange: (description?: string) => void }> = ({ refreshTrigger, handleDatabaseChange }) => {
    const [accounts, setAccounts] = useState<Account[]>([]);
    const [loading, setLoading] = useState(true);
    const [modal, setModal] = useState<{ type: 'add' | 'edit' | 'delete' | 'details' | null, account: Account | null }>({ type: null, account: null });
    const toast = useToast();

    const fetchAccounts = useCallback(async () => {
        setLoading(true);
        const { data, error } = await supabase.from('accounts').select('*').order('name');
        if (!error && data) setAccounts(data as Account[]);
        setLoading(false);
    }, []);

    useEffect(() => { fetchAccounts(); }, [fetchAccounts, refreshTrigger]);

    const totalWealth = useMemo(() => accounts.reduce((sum, acc) => sum + acc.balance, 0), [accounts]);

    const handleDelete = async () => {
        if (!modal.account) return;
        const { error } = await supabase.from('accounts').delete().eq('id', modal.account.id);
        if(!error) { 
            logActivity(`حذف حساب: ${modal.account.name}`); 
            setModal({type:null, account:null}); 
            handleDatabaseChange(); 
            toast.success("تم الحذف"); 
        } else {
            toast.error("لا يمكن الحذف لارتباطه بعمليات سابقة");
        }
    };

    return (
        <div className="space-y-8 pb-24 max-w-6xl mx-auto px-1">
            {/* Header Wealth Section */}
            <div className="glass-card p-10 rounded-[2.5rem] border border-white/5 bg-gradient-to-br from-slate-900 to-slate-950 relative overflow-hidden animate-slide-up">
                <div className="absolute top-0 right-0 w-96 h-96 bg-cyan-500/10 rounded-full blur-[120px]"></div>
                <div className="relative z-10">
                    <p className="text-slate-500 font-black text-xs uppercase tracking-[0.3em] mb-3 flex items-center gap-2">
                        صافي الأرصدة المتوفرة <InformationCircleIcon className="w-4 h-4 opacity-50" />
                    </p>
                    <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
                        <h1 className="text-5xl md:text-7xl font-black text-white tracking-tighter tabular-nums">
                            {formatCurrency(totalWealth)}
                        </h1>
                        <button 
                            onClick={() => setModal({ type: 'add', account: null })} 
                            className="bg-white text-slate-950 px-8 py-4 rounded-[1.5rem] font-black text-sm hover:bg-cyan-50 transition-all flex items-center justify-center gap-3 shadow-2xl active:scale-95 group shrink-0"
                        >
                            إضافة حساب جديد <PlusIcon className="w-6 h-6 group-hover:rotate-90 transition-transform" />
                        </button>
                    </div>
                </div>
            </div>

            {/* Grid of Accounts */}
            {loading ? (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {[1,2,3].map(i => <div key={i} className="h-48 bg-slate-800/40 rounded-[2rem] animate-pulse"></div>)}
                </div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {accounts.map((acc, index) => {
                        const theme = THEME_OPTIONS.find(t => t.id === (acc.theme || getDefaultThemeForType(acc.type))) || THEME_OPTIONS[0];
                        const TypeIcon = getAccountTypeIcon(acc.type);
                        return (
                            <div 
                                key={acc.id} 
                                onClick={() => setModal({ type: 'details', account: acc })}
                                className={`group relative rounded-[2.5rem] p-8 text-white shadow-2xl transition-all duration-500 border cursor-pointer hover:scale-[1.03] active:scale-95 animate-slide-up ${theme.class}`}
                                style={{ animationDelay: `${index * 50}ms` }}
                            >
                                <div className="absolute inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-10 rounded-[2.5rem] pointer-events-none"></div>

                                <div className="relative z-10 flex justify-between items-start mb-10">
