                                        <div>
                                            <p className="text-xs font-black tracking-tight text-white">{acc.name}</p>
                                            <p className="text-[9px] font-bold text-white/50">{acc.type}</p>
                                        </div>
                                        <ChevronLeftIcon className="w-5 h-5 text-white/30 group-hover:text-white transition-colors" />
                                    </div>
                                </div>
                            </div>
                        );
                    })}
                </div>
            )}

            {/* Modals */}
            {(modal.type === 'add' || modal.type === 'edit') && (
                <div className="fixed inset-0 z-[100] bg-slate-950/90 backdrop-blur-xl flex items-center justify-center p-4 animate-fade-in pt-safe pb-safe">
                    <div className="relative w-full max-w-md bg-slate-900 rounded-[2.5rem] shadow-2xl border border-white/10 p-8 animate-slide-up">
                        <div className="flex justify-between items-center mb-8">
