const AccountDetailsModal: React.FC<{
    account: Account;
    onClose: () => void;
    onEdit: () => void;
    onDelete: () => void;
}> = ({ account, onClose, onEdit, onDelete }) => {
    const [transactions, setTransactions] = useState<Transaction[]>([]);
    const [loading, setLoading] = useState(true);
    const [stats, setStats] = useState({ income: 0, expense: 0 });

    useEffect(() => {
        const fetchData = async () => {
            setLoading(true);
            const { data: txs } = await supabase
                .from('transactions')
                .select('*, categories(name, icon, color), accounts:account_id(name)')
                .or(`account_id.eq.${account.id},to_account_id.eq.${account.id}`)
                .order('date', { ascending: false })
                .limit(10);

            if (txs) {
                setTransactions(txs as unknown as Transaction[]);
                let inc = 0, exp = 0;
                txs.forEach((t: any) => {
                    if (t.type === 'income' && t.account_id === account.id) inc += t.amount;
                    if (t.type === 'expense' && t.account_id === account.id) exp += t.amount;
                });
                setStats({ income: inc, expense: exp });
            }
            setLoading(false);
        };
        fetchData();
    }, [account.id]);

    const theme = PREMIUM_THEMES.find(t => t.id === account.theme) || PREMIUM_THEMES[0];

    return (
        <div className="fixed inset-0 z-[100] bg-black/90 backdrop-blur-xl flex items-center justify-center p-4 animate-fade-in pt-safe pb-safe">
            <div className="relative w-full max-w-lg bg-[#0a0a0a] rounded-[3rem] shadow-2xl border border-white/5 flex flex-col max-h-[85vh] overflow-hidden animate-slide-up">
                {/* Header Card Area */}
                <div className={`shrink-0 p-8 relative overflow-hidden ${theme.class}`}>
                    {/* Artistic Mesh Gradient Background */}
                    <div className="absolute inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-20 pointer-events-none mix-blend-overlay"></div>
                    <div className={`absolute -top-24 -right-24 w-64 h-64 bg-gradient-to-br ${theme.gradient} rounded-full blur-[80px] opacity-60`}></div>

                    <div className="relative z-10 flex justify-between items-start text-white mb-10">
                        <div className="w-12 h-12 rounded-2xl bg-white/10 backdrop-blur-md flex items-center justify-center border border-white/10">
                            {React.createElement(getAccountTypeIcon(account.type), { className: "w-6 h-6" })}
                        </div>
                        <button onClick={onClose} className="p-3 rounded-full bg-black/20 text-white/50 hover:text-white transition-colors">
                            <XMarkIcon className="w-6 h-6" />
                        </button>
                    </div>

                    <div className="relative z-10">
                        <h2 className="text-sm font-bold text-white/60 mb-1 tracking-wider uppercase">{account.name}</h2>
                        <h3 className="text-5xl font-black text-white tracking-tighter tabular-nums">{formatCurrency(account.balance, account.currency)}</h3>
