                            <p className="text-[10px] font-black text-emerald-400 uppercase mb-1">وارد</p>
                            <p className="text-xl font-bold text-white">+{formatCurrency(stats.income)}</p>
                        </div>
                        <div className="bg-slate-900/50 p-5 rounded-3xl border border-white/5">
                            <p className="text-[10px] font-black text-rose-400 uppercase mb-1">صادر</p>
                            <p className="text-xl font-bold text-white">-{formatCurrency(stats.expense)}</p>
                        </div>
                    </div>

                    <h4 className="text-xs font-black text-slate-500 uppercase tracking-[0.2em] mb-4">المعاملات الأخيرة</h4>
                    {loading ? (
                        <div className="space-y-3">{[1,2,3].map(i => <div key={i} className="h-16 bg-slate-900 rounded-2xl animate-pulse"></div>)}</div>
                    ) : transactions.length === 0 ? (
                        <div className="text-center py-10 opacity-30">لا توجد سجلات</div>
                    ) : (
                        <div className="space-y-3">
                            {transactions.map(tx => {
                                const isIncome = tx.type === 'income' || (tx.type === 'transfer' && tx.to_account_id === account.id);
                                return (
                                    <div key={tx.id} className="flex items-center justify-between p-4 bg-slate-900/40 rounded-2xl border border-white/5">
                                        <div className="flex items-center gap-3">
