const AccountForm: React.FC<{ account?: Account | null; onSave: () => void; onCancel: () => void; }> = ({ account, onSave, onCancel }) => {
    const toast = useToast();
    const [name, setName] = useState(account?.name || '');
    const [type, setType] = useState(account?.type || 'بنكي');
    const [balance, setBalance] = useState(account?.balance?.toString() || '0');
    const [theme, setTheme] = useState(account?.theme || 'midnight');
    const [isSaving, setIsSaving] = useState(false);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsSaving(true);
        const data = { name, type, balance: parseFloat(balance), theme };
        const { error } = account?.id 
            ? await supabase.from('accounts').update(data).eq('id', account.id) 
            : await supabase.from('accounts').insert(data);

        if (error) toast.error('فشل في حفظ البيانات');
        else onSave();
        setIsSaving(false);
    };

    return (
        <form onSubmit={handleSubmit} className="space-y-6">
            <div className="space-y-4">
                <div>
                    <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-2 block">اسم الحساب</label>
                    <input type="text" value={name} onChange={e => setName(e.target.value)} required className="w-full bg-slate-900 border border-white/10 rounded-2xl p-4 text-white focus:outline-none focus:border-cyan-500 transition-all" placeholder="مثلاً: المحفظة الشخصية" />
                </div>
                <div className="grid grid-cols-2 gap-4">
                    <div>
                        <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-2 block">نوع الحساب</label>
                        <select value={type} onChange={e => setType(e.target.value)} className="w-full bg-slate-900 border border-white/10 rounded-2xl p-4 text-white focus:outline-none">
                            <option value="بنكي">بنكي</option>
                            <option value="نقدي">نقدي</option>
                            <option value="مخصص">مخصص</option>
                        </select>
                    </div>
                    <div>
                        <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-2 block">الرصيد</label>
                        <input type="number" step="0.01" value={balance} onChange={e => setBalance(e.target.value)} required className="w-full bg-slate-900 border border-white/10 rounded-2xl p-4 text-white focus:outline-none" />
                    </div>
                </div>
                <div>
                    <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-3 block">لون البطاقة</label>
                    <div className="grid grid-cols-5 gap-3">
                        {PREMIUM_THEMES.map(opt => (
                            <button 
                                key={opt.id} 
                                type="button" 
                                onClick={() => setTheme(opt.id)} 
                                className={`h-10 w-10 rounded-full border-2 transition-all flex items-center justify-center ${theme === opt.id ? 'border-white scale-110 shadow-lg' : 'border-transparent opacity-40 hover:opacity-100'} ${opt.class}`}
                            >
                                {theme === opt.id && <CheckCircleIcon className="w-4 h-4 text-white" />}
                            </button>
                        ))}
                    </div>
                </div>
            </div>
            <button type="submit" disabled={isSaving} className="w-full py-5 bg-gradient-to-r from-cyan-600 to-blue-600 text-white rounded-3xl font-black shadow-xl active:scale-95 transition-all">
                {isSaving ? 'جاري الحفظ...' : 'تأكيد وحفظ'}
            </button>
        </form>
    );
};

const AccountsPage: React.FC<{ refreshTrigger: number, handleDatabaseChange: (description?: string) => void }> = ({ refreshTrigger, handleDatabaseChange }) => {
    const [accounts, setAccounts] = useState<Account[]>([]);
    const [loading, setLoading] = useState(true);
    const [modal, setModal] = useState<{ type: 'add' | 'edit' | 'delete' | 'details' | null, account: Account | null }>({ type: null, account: null });
    const toast = useToast();

    const fetchAccounts = useCallback(async () => {
        setLoading(true);
        const { data, error } = await supabase.from('accounts').select('*').order('name');
        if (!error && data) setAccounts(data as Account[]);
        setLoading(false);
    }, []);

    useEffect(() => { fetchAccounts(); }, [fetchAccounts, refreshTrigger]);

    const totalWealth = useMemo(() => accounts.reduce((sum, acc) => sum + acc.balance, 0), [accounts]);

    const handleDelete = async () => {
        if (!modal.account) return;
        const { error } = await supabase.from('accounts').delete().eq('id', modal.account.id);
        if(!error) { 
            logActivity(`حذف حساب: ${modal.account.name}`); 
            setModal({type:null, account:null}); 
            handleDatabaseChange(); 
            toast.success("تم الحذف"); 
        } else {
            toast.error("لا يمكن الحذف لارتباطه بعمليات سابقة");
        }
    };

    return (
        <div className="space-y-10 pb-32 max-w-6xl mx-auto px-2">
            {/* Header Section */}
            <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 px-2 animate-slide-up">
                <div>
                    <p className="text-slate-500 font-black text-xs uppercase tracking-[0.4em] mb-2 flex items-center gap-2">
                        إجمالي الأرصدة المتاحة <SparklesIcon className="w-4 h-4 text-cyan-500" />
                    </p>
                    <h1 className="text-6xl font-black text-white tracking-tighter tabular-nums">
                        {formatCurrency(totalWealth)}
                    </h1>
                </div>
                <button 
                    onClick={() => setModal({ type: 'add', account: null })} 
                    className="h-16 px-10 bg-white text-black rounded-[2rem] font-black text-sm transition-all flex items-center justify-center gap-3 shadow-[0_0_40px_rgba(255,255,255,0.1)] active:scale-95 shrink-0"
                >
                    <PlusIcon className="w-6 h-6" /> إضافة حساب
                </button>
            </div>

            {/* Premium Grid */}
            {loading ? (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                    {[1,2,3].map(i => <div key={i} className="h-64 bg-slate-900/50 rounded-[3rem] animate-pulse border border-white/5"></div>)}
                </div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                    {accounts.map((acc, index) => {
                        const theme = PREMIUM_THEMES.find(t => t.id === acc.theme) || PREMIUM_THEMES[0];
                        const TypeIcon = getAccountTypeIcon(acc.type);
                        return (
                            <div 
                                key={acc.id} 
                                onClick={() => setModal({ type: 'details', account: acc })}
                                className={`group relative h-64 rounded-[3rem] p-10 text-white shadow-2xl transition-all duration-700 border border-white/5 cursor-pointer hover:scale-[1.02] active:scale-95 animate-slide-up overflow-hidden ${theme.class}`}
                                style={{ animationDelay: `${index * 100}ms` }}
                            >
                                {/* Professional Decorative Layer */}
                                <div className="absolute inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-10 pointer-events-none mix-blend-soft-light"></div>
                                <div className={`absolute -top-20 -right-20 w-64 h-64 bg-gradient-to-br ${theme.gradient} rounded-full blur-[80px] opacity-50 group-hover:opacity-80 transition-opacity duration-1000`}></div>

                                <div className="relative z-10 flex justify-between items-start h-full flex-col">
                                    <div className="flex justify-between items-center w-full">
                                        <div className="w-14 h-14 bg-white/10 backdrop-blur-xl rounded-2xl flex items-center justify-center border border-white/10 group-hover:rotate-6 transition-transform">
                                            <TypeIcon className="w-7 h-7 text-white" />
                                        </div>
                                        <div className="opacity-40 group-hover:opacity-100 transition-opacity">
                                            <ChevronLeftIcon className="w-6 h-6" />
                                        </div>
                                    </div>

                                    <div>
                                        <p className="text-[11px] font-black uppercase tracking-[0.3em] text-white/50 mb-1">{acc.type}</p>
                                        <h3 className="text-3xl font-black mb-6 truncate max-w-[200px]">{acc.name}</h3>
                                        <h4 className="text-4xl font-black tabular-nums tracking-tighter">{formatCurrency(acc.balance, acc.currency)}</h4>
                                    </div>
                                </div>
                            </div>
                        );
                    })}
                </div>
            )}

            {/* Modal Components */}
            {(modal.type === 'add' || modal.type === 'edit') && (
                <div className="fixed inset-0 z-[100] bg-black/90 backdrop-blur-xl flex items-center justify-center p-4 animate-fade-in pt-safe pb-safe">
                    <div className="relative w-full max-w-md bg-[#0a0a0a] rounded-[3rem] shadow-2xl border border-white/10 p-10 animate-slide-up">
                        <div className="flex justify-between items-center mb-8">
                            <h3 className="text-2xl font-black text-white">{modal.type === 'add' ? 'فتح حساب' : 'تعديل'}</h3>
                            <button onClick={() => setModal({ type: null, account: null })} className="p-2 text-slate-500 hover:text-white"><XMarkIcon className="w-6 h-6" /></button>
                        </div>
                        <AccountForm account={modal.account} onSave={() => { setModal({type:null, account:null}); handleDatabaseChange(); fetchAccounts(); }} onCancel={() => setModal({ type: null, account: null })} />
                    </div>
                </div>
            )}

            {modal.type === 'details' && modal.account && (
                <AccountDetailsModal 
                    account={modal.account} 
                    onClose={() => setModal({ type: null, account: null })} 
                    onEdit={() => setModal({ type: 'edit', account: modal.account })} 
                    onDelete={() => setModal({ type: 'delete', account: modal.account })} 
                />
            )}

            <ConfirmDialog 
                isOpen={modal.type === 'delete' && !!modal.account} 
                title="حذف الحساب" 
                message={`هل أنت متأكد من رغبتك في حذف حساب "${modal.account?.name}"؟ سيتم حذف كافة السجلات المرتبطة به.`} 
                confirmText="نعم، احذف" 
                onConfirm={handleDelete} 
                onCancel={() => setModal({ type: null, account: null })} 
            />
        </div>
    );
};

