const AccountForm: React.FC<{ account?: Account | null; onSave: () => void; onCancel: () => void; }> = ({ account, onSave, onCancel }) => {
    const toast = useToast();
    const [name, setName] = useState(account?.name || '');
    const [type, setType] = useState(account?.type || 'بنكي');
    const [balance, setBalance] = useState(account?.balance?.toString() || '0');
    const [isSaving, setIsSaving] = useState(false);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsSaving(true);
        const data = { name, type, balance: parseFloat(balance) };
        const { error } = account?.id 
            ? await supabase.from('accounts').update(data).eq('id', account.id) 
            : await supabase.from('accounts').insert(data);

        if (error) toast.error('فشل في حفظ البيانات');
        else onSave();
        setIsSaving(false);
    };

    return (
        <form onSubmit={handleSubmit} className="space-y-8">
            <div className="space-y-5">
                <div className="relative group">
                    <label className="text-[10px] font-black text-slate-500 uppercase tracking-[0.3em] mb-2 block px-2">مسمى الحساب</label>
                    <input type="text" value={name} onChange={e => setName(e.target.value)} required className="w-full bg-[#111] border border-white/5 rounded-2xl p-5 text-white focus:outline-none focus:border-white/20 transition-all text-lg font-bold" placeholder="مثلاً: المحفظة الرئيسية" />
                </div>
                <div className="grid grid-cols-2 gap-4">
                    <div>
                        <label className="text-[10px] font-black text-slate-500 uppercase tracking-[0.3em] mb-2 block px-2">التصنيف</label>
                        <select value={type} onChange={e => setType(e.target.value)} className="w-full bg-[#111] border border-white/5 rounded-2xl p-5 text-white focus:outline-none font-bold">
