                            <tr key={d.id} className={i % 2 === 0 ? 'bg-white' : 'bg-slate-50'}>
                                <td className="p-4 font-mono text-slate-500 border-b border-slate-100">{new Date(d.created_at).toLocaleDateString('ar-LY')}</td>
