                </div> 
                <div> 
                    <label className="text-sm font-medium text-slate-400 mb-2 block">حالة الاستحقاق</label> 
                    <div className="flex gap-2"> 
                        {dueDateStatusOptions.map(({ key, label }) => ( <button key={key} onClick={() => setTempFilters(f => ({ ...f, dueDateStatus: key }))} className={`flex-1 py-2 px-2 rounded-xl text-sm transition-colors font-bold border ${tempFilters.dueDateStatus === key ? 'bg-cyan-500/20 border-cyan-500 text-cyan-400' : 'bg-slate-800 border-slate-700 text-slate-400 hover:bg-slate-700'}`}> {label} </button> ))} 
                    </div> 
                </div> 
            </div> 
            <div className="flex justify-between items-center pt-6 mt-4 border-t border-white/10"> 
                <button onClick={handleReset} className="py-2 px-4 text-slate-400 hover:text-white font-bold text-sm">إعادة تعيين</button> 
                <button onClick={handleApply} className="py-2.5 px-6 bg-cyan-600 hover:bg-cyan-500 text-white rounded-xl transition font-bold shadow-lg">تطبيق</button> 
            </div> 
        </Modal> 
    ); 
};

// Main Page Component
const DebtsPage: React.FC<{ refreshTrigger: number, handleDatabaseChange: (description?: string) => void, onSelectContact: (contactId: string) => void }> = ({ refreshTrigger, handleDatabaseChange, onSelectContact }) => {
    const toast = useToast();
    const [debts, setDebts] = useState<Debt[]>([]);
    const [contacts, setContacts] = useState<Contact[]>([]);
    const [accounts, setAccounts] = useState<Account[]>([]);
    const [categories, setCategories] = useState<Category[]>([]);

    const [loading, setLoading] = useState(true);
    const [isFormModalOpen, setIsFormModalOpen] = useState(false);
    const [isFilterModalOpen, setIsFilterModalOpen] = useState(false);
    const [editingDebt, setEditingDebt] = useState<Debt | undefined>(undefined);
    const [deletingDebt, setDeletingDebt] = useState<Debt | null>(null);
    const [settlingDebt, setSettlingDebt] = useState<Debt | null>(null);
    const [splittingDebt, setSplittingDebt] = useState<Debt | null>(null);
    const [detailsDebt, setDetailsDebt] = useState<Debt | null>(null);
    const [searchTerm, setSearchTerm] = useState('');
    const [filters, setFilters] = useState<DebtFilterValues>({
        status: 'unpaid',
        dueDateStatus: 'all',
    });

    const [activeTab, setActiveTab] = useState<'on_you' | 'for_you'>('for_you');

    useEffect(() => {
        const fetchData = async () => {
            setLoading(true);
            const debtsPromise = supabase.from('debts').select('*, contacts(*), accounts(name)').order('due_date');
            const contactsPromise = supabase.from('contacts').select('*').order('name');
            const accountsPromise = supabase.from('accounts').select('*');
            const categoriesPromise = supabase.from('categories').select('*');

            const [
                {data: debtsData, error: debtsError}, 
                {data: contactsData, error: contactsError},
                {data: accountsData, error: accountsError},
                {data: categoriesData, error: categoriesError},
            ] = await Promise.all([debtsPromise, contactsPromise, accountsPromise, categoriesPromise]);

            if (debtsError) console.error('Error fetching debts:', debtsError.message);
            else if (debtsData) setDebts(debtsData as unknown as Debt[]);

            if (contactsError) console.error('Error fetching contacts:', contactsError.message);
            else if (contactsData) setContacts(contactsData as unknown as Contact[]);

            if (accountsError) console.error('Error fetching accounts:', accountsError.message);
            else setAccounts(accountsData || []);

            if (categoriesError) console.error('Error fetching categories:', categoriesError.message);
            else setCategories(categoriesData || []);

            setLoading(false);
        };
        fetchData();
    }, [refreshTrigger]);

    const handleSaveForm = () => {
        const description = editingDebt ? `تم تعديل بيانات الدين بنجاح` : 'تم تسجيل الدين الجديد بنجاح';
        setIsFormModalOpen(false);
        setEditingDebt(undefined);
        handleDatabaseChange(description);
        toast.success(description);
    };

    const handleDelete = async () => {
        if (!deletingDebt) return;
        const description = `تم حذف الدين بنجاح`;
        const { error } = await supabase.from('debts').delete().eq('id', deletingDebt.id);
        if (error) {
            console.error('Error deleting debt', error.message);
            toast.error('حدث خطأ أثناء الحذف.');
        } else {
            const contactName = deletingDebt.contacts?.name || 'مجهول';
            logActivity(`حذف دين: ${formatCurrency(deletingDebt.amount)} لـ ${contactName}`);

            setDeletingDebt(null);
            handleDatabaseChange(description);
            toast.success(description);
        }
    };

    const handleWhatsAppReminder = (debt: Debt) => {
        if (!debt.contacts) return;
        const name = debt.contacts.name;
        const amount = formatCurrency(debt.amount);
        const date = debt.due_date ? new Date(debt.due_date).toLocaleDateString('ar-LY') : 'غير محدد';
        const phone = debt.contacts.phone || '';

        const message = `مرحباً ${name}، أتمنى أن تكون بخير. أردت فقط إرسال تذكير ودي بخصوص المبلغ المستحق (${amount}) والمقيد بتاريخ ${date}. شكراً لك سلفاً.`;
        const encodedMessage = encodeURIComponent(message);

        window.open(`https://wa.me/${phone.replace(/\+/g, '')}?text=${encodedMessage}`, '_blank');
    };

    const handleSplitDebt = async (months: number, startDate: string) => {
        if (!splittingDebt) return;
        const amountPerMonth = splittingDebt.amount / months;
        const installments = [];

        let currentDate = new Date(startDate);
        for (let i = 0; i < months; i++) {
            const dueDate = new Date(currentDate);
            dueDate.setMonth(dueDate.getMonth() + i);

            installments.push({
                contact_id: splittingDebt.contact_id,
                amount: amountPerMonth,
                type: splittingDebt.type,
                due_date: dueDate.toISOString().split('T')[0],
                description: `${splittingDebt.description || 'دين'} - قسط ${i + 1}/${months}`,
                paid: false
            });
        }

        try {
            // Delete original
            await supabase.from('debts').delete().eq('id', splittingDebt.id);
            // Insert new ones
            await supabase.from('debts').insert(installments);

            logActivity(`تقسيم دين ${splittingDebt.contacts?.name} إلى ${months} أقساط`);
            handleDatabaseChange('تم تقسيم الدين بنجاح');
            toast.success('تم إنشاء الأقساط المجدولة');
            setSplittingDebt(null);
        } catch (err) {
            toast.error('خطأ في تقسيم الدين');
        }
    };

    const togglePaidStatus = async (debt: Debt) => {
        const { error } = await supabase.from('debts').update({ paid: !debt.paid, paid_at: null }).eq('id', debt.id);
         if (error) {
            console.error('Error updating debt status', error.message);
            toast.error('حدث خطأ أثناء تحديث حالة الدين.');
        } else {
            const description = `تم تغيير حالة الدين إلى ${!debt.paid ? 'مدفوع' : 'غير مدفوع'}`;
            const contactName = debt.contacts?.name || 'مجهول';
            logActivity(`تغيير حالة دين ${contactName} إلى ${!debt.paid ? 'مدفوع' : 'غير مدفوع'}`);

            handleDatabaseChange(description);
            toast.success(description);
        }
    };

    const handleDebtAction = (debt: Debt) => {
        if (debt.paid) {
            togglePaidStatus(debt);
        } else {
            setSettlingDebt(debt);
        }
    };

    const handleConfirmSettlement = async (accountId: string) => {
        if (!settlingDebt) return;

        try {
            const transactionType = settlingDebt.type === 'on_you' ? 'expense' : 'income';
            const amount = settlingDebt.amount;
            const sign = transactionType === 'expense' ? -1 : 1;

            const categoryType = transactionType;
            const categoryName = categoryType === 'income' ? 'تحصيل ديون' : 'ديون وقروض';
            let debtCategory = categories.find(c => c.name === categoryName && c.type === categoryType);

            if (!debtCategory) {
                 const { data: newCategory, error: catError } = await supabase.from('categories').insert({
                     name: categoryName,
                     type: categoryType,
                     icon: 'CurrencyDollarIcon',
                     color: '#64748b'
                 }).select().single();

                 if (catError) throw catError;
                 debtCategory = newCategory;
            }

            // Update Account Balance
            const { data: account, error: accFetchError } = await supabase.from('accounts').select('balance, name').eq('id', accountId).single();
            if(accFetchError || !account) throw new Error("Account not found");

            const { error: accUpdateError } = await supabase.from('accounts').update({ balance: account.balance + (amount * sign) }).eq('id', accountId);
            if(accUpdateError) throw accUpdateError;

            // Create Transaction
            const { error: txError } = await supabase.from('transactions').insert({
                amount: amount,
                type: transactionType,
                account_id: accountId,
                category_id: debtCategory?.id,
                date: new Date().toISOString(),
                notes: `تسوية دين: ${settlingDebt.description || 'بدون وصف'}`
            });

            if (txError) throw txError;

            // Mark debt as paid
            const { error: debtUpdateError } = await supabase.from('debts').update({ paid: true, paid_at: new Date().toISOString() }).eq('id', settlingDebt.id);
            if (debtUpdateError) throw debtUpdateError;

            const description = 'تم تسوية الدين بنجاح';
            const contactName = settlingDebt.contacts?.name || 'مجهول';
            logActivity(`تسوية دين (${contactName}): ${formatCurrency(amount)} عبر حساب ${account.name}`);

            handleDatabaseChange(description);
            toast.success(description);
            setSettlingDebt(null);

        } catch (error: any) {
            console.error('Error settling debt:', error.message);
            toast.error('حدث خطأ أثناء تسوية الدين.');
        }
    };

    const filteredDebts = useMemo(() => {
        return debts.filter(debt => {
            const matchesTab = debt.type === activeTab;
            const matchesSearch = !searchTerm || 
                debt.description?.toLowerCase().includes(searchTerm.toLowerCase()) || 
                debt.contacts?.name?.toLowerCase().includes(searchTerm.toLowerCase());

            let matchesStatus = true;
            if (filters.status === 'paid') matchesStatus = debt.paid;
            if (filters.status === 'unpaid') matchesStatus = !debt.paid;

            let matchesDueDate = true;
            const status = getDebtStatus(debt.due_date);
            if (filters.dueDateStatus === 'overdue') matchesDueDate = status === 'overdue' && !debt.paid;
            if (filters.dueDateStatus === 'due_soon') matchesDueDate = status === 'due_soon' && !debt.paid;

            return matchesTab && matchesSearch && matchesStatus && matchesDueDate;
        });
    }, [debts, activeTab, searchTerm, filters]);

    const activeFilterCount = useMemo(() => {
        let count = 0;
        if(filters.status !== 'unpaid') count++;
        if(filters.dueDateStatus !== 'all') count++;
        return count;
    }, [filters]);

    const stats = useMemo(() => {
        const currentDebts = debts.filter(d => !d.paid);
        return {
            onYou: currentDebts.filter(d => d.type === 'on_you').reduce((sum, d) => sum + d.amount, 0),
            forYou: currentDebts.filter(d => d.type === 'for_you').reduce((sum, d) => sum + d.amount, 0)
        };
    }, [debts]);

    return (
        <div className="space-y-6 pb-24">
            {/* Header Cards */}
            <div className="grid grid-cols-2 gap-4">
                <button onClick={() => setActiveTab('for_you')} className={`glass-card p-4 rounded-2xl border transition-all duration-300 relative overflow-hidden group ${activeTab === 'for_you' ? 'bg-emerald-500/10 border-emerald-500/50 shadow-lg shadow-emerald-500/10' : 'bg-slate-900/50 border-white/5 hover:bg-slate-800'}`}>
                    <div className="relative z-10">
                        <p className={`text-xs font-bold mb-1 ${activeTab === 'for_you' ? 'text-emerald-400' : 'text-slate-400'}`}>لك (تحصيل)</p>
                        <p className="text-2xl font-black text-white">{formatCurrency(stats.forYou)}</p>
                    </div>
                    {activeTab === 'for_you' && <div className="absolute -bottom-4 -right-4 w-20 h-20 bg-emerald-500/20 rounded-full blur-xl"></div>}
                </button>
                <button onClick={() => setActiveTab('on_you')} className={`glass-card p-4 rounded-2xl border transition-all duration-300 relative overflow-hidden group ${activeTab === 'on_you' ? 'bg-rose-500/10 border-rose-500/50 shadow-lg shadow-rose-500/10' : 'bg-slate-900/50 border-white/5 hover:bg-slate-800'}`}>
                    <div className="relative z-10">
                        <p className={`text-xs font-bold mb-1 ${activeTab === 'on_you' ? 'text-rose-400' : 'text-slate-400'}`}>عليك (سداد)</p>
                        <p className="text-2xl font-black text-white">{formatCurrency(stats.onYou)}</p>
                    </div>
                     {activeTab === 'on_you' && <div className="absolute -bottom-4 -right-4 w-20 h-20 bg-rose-500/20 rounded-full blur-xl"></div>}
                </button>
            </div>

            {/* Controls */}
            <div className="flex gap-3 items-center">
                 <div className="relative flex-grow group">
                    <MagnifyingGlassIcon className="absolute right-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400 group-focus-within:text-cyan-400 transition-colors pointer-events-none" />
                    <input type="text" placeholder="ابحث في الديون..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)}
                        className="w-full bg-slate-900/50 p-3 pr-12 rounded-2xl text-white border border-slate-700 focus:border-cyan-500 focus:ring-1 focus:ring-cyan-500 focus:outline-none transition shadow-inner" />
                </div>
                <button onClick={() => setIsFilterModalOpen(true)} className={`relative flex-shrink-0 flex items-center justify-center h-12 w-12 rounded-2xl transition-all ${activeFilterCount > 0 ? 'bg-cyan-500/20 text-cyan-400 border border-cyan-500/50' : 'bg-slate-800 text-slate-400 border border-slate-700 hover:bg-slate-700'}`}>
                    <FunnelIcon className="w-5 h-5"/>
                    {activeFilterCount > 0 && <span className="absolute -top-1 -right-1 h-4 w-4 bg-cyan-500 text-white text-[10px] font-bold rounded-full flex items-center justify-center shadow-sm">{activeFilterCount}</span>}
                </button>
            </div>

            {/* Debts List */}
            {loading ? <div className="space-y-3">{[...Array(3)].map((_,i) => <div key={i} className="h-24 bg-slate-800/50 rounded-2xl animate-pulse"></div>)}</div>
            : filteredDebts.length === 0 ? <div className="text-center py-16 bg-slate-900/20 rounded-3xl border-dashed border-2 border-slate-800 text-slate-500">لا توجد ديون تطابق بحثك.</div>
            : (
                <div className="space-y-3">
                    {filteredDebts.map(debt => {
                        const status = getDebtStatus(debt.due_date);
                        const isPayable = debt.type === 'on_you';

                        return (
                            <div key={debt.id} onClick={() => setDetailsDebt(debt)} 
                                className={`relative group p-4 rounded-2xl border transition-all cursor-pointer hover:shadow-lg hover:-translate-y-1 ${debt.paid ? 'bg-slate-900/30 border-slate-800 opacity-60' : 'bg-slate-900/80 border-white/5 hover:border-white/10'}`}
                            >
                                <div className="flex justify-between items-start mb-2">
                                    <div className="flex items-center gap-3">
                                        <div className={`w-10 h-10 rounded-full flex items-center justify-center font-bold text-white shadow-md ${isPayable ? 'bg-rose-500' : 'bg-emerald-500'}`}>
                                            {debt.contacts?.name?.charAt(0) || '?'}
                                        </div>
                                        <div>
                                            <p className="font-bold text-white text-base">{debt.contacts?.name || 'غير معروف'}</p>
                                            <p className="text-xs text-slate-400 truncate max-w-[150px]">{debt.description || 'بدون وصف'}</p>
                                        </div>
                                    </div>
                                    <div className="flex flex-col items-end">
                                        <p className={`font-extrabold text-lg ${isPayable ? 'text-rose-400' : 'text-emerald-400'} ${debt.paid ? 'line-through text-slate-500' : ''}`}>
                                            {formatCurrency(debt.amount)}
                                        </p>
                                        {!debt.paid && !isPayable && (
                                            <button 
                                                onClick={(e) => { e.stopPropagation(); handleWhatsAppReminder(debt); }}
                                                className="mt-1 flex items-center gap-1 px-2 py-1 bg-emerald-500/10 text-emerald-500 rounded-lg text-[9px] font-black hover:bg-emerald-500 hover:text-white transition-all"
                                            >
                                                <WhatsappIcon className="w-3 h-3" /> تذكير
                                            </button>
                                        )}
                                    </div>
                                </div>

                                <div className="flex justify-between items-center mt-3 pt-3 border-t border-white/5">
                                    <div className="flex items-center gap-2">
                                        {status === 'overdue' && !debt.paid && <span className="text-[10px] font-bold text-rose-400 flex items-center gap-1 bg-rose-500/10 px-2 py-1 rounded-md"><ExclamationTriangleIcon className="w-3 h-3"/> متأخر</span>}
                                        {status === 'due_soon' && !debt.paid && <span className="text-[10px] font-bold text-amber-400 flex items-center gap-1 bg-amber-500/10 px-2 py-1 rounded-md"><ExclamationTriangleIcon className="w-3 h-3"/> قريباً</span>}
                                        {debt.due_date && <span className="text-[10px] text-slate-500 font-mono">{new Date(debt.due_date).toLocaleDateString('ar-LY')}</span>}
                                    </div>

                                    <div className="flex gap-1 items-center" onClick={e => e.stopPropagation()}>
                                        {!debt.paid && (
                                            <button 
                                                onClick={() => setSplittingDebt(debt)} 
                                                title="تقسيم لأقساط"
                                                className="p-2 text-slate-500 hover:text-cyan-400 hover:bg-white/5 rounded-lg transition"
                                            >
                                                <SquaresPlusIcon className="w-4 h-4"/>
                                            </button>
                                        )}
                                        <button onClick={() => { setEditingDebt(debt); setIsFormModalOpen(true); }} className="p-2 text-slate-500 hover:text-cyan-400 hover:bg-white/5 rounded-lg transition"><PencilSquareIcon className="w-4 h-4"/></button>
                                        <button onClick={() => setDeletingDebt(debt)} className="p-2 text-slate-500 hover:text-rose-400 hover:bg-white/5 rounded-lg transition"><TrashIcon className="w-4 h-4"/></button>
                                        {!debt.paid && (
                                            <button 
                                                onClick={() => handleDebtAction(debt)} 
                                                className={`px-3 py-1.5 rounded-lg text-xs font-bold transition-all ml-1 ${isPayable ? 'bg-rose-500/20 text-rose-400 hover:bg-rose-500 hover:text-white' : 'bg-emerald-500/20 text-emerald-400 hover:bg-emerald-500 hover:text-white'}`}
                                            >
                                                {isPayable ? 'سداد' : 'تحصيل'}
                                            </button>
                                        )}
                                    </div>
                                </div>
                            </div>
                        )
                    })}
                </div>
            )}

            {/* Centered FAB */}
            <button 
                onClick={() => setIsFormModalOpen(true)} 
                className="fixed bottom-4 left-1/2 -translate-x-1/2 z-40 h-16 w-16 bg-slate-900 rounded-full shadow-[0_0_20px_rgba(8,145,178,0.4)] flex items-center justify-center transition-all duration-300 border-4 border-slate-900 overflow-visible hover:scale-105 active:scale-95 group"
            >
                <div className="absolute inset-1 bg-gradient-to-r from-cyan-500 to-blue-600 rounded-full flex items-center justify-center">
                    <PlusIcon className="w-8 h-8 text-white transition-transform duration-300 group-hover:rotate-90"/>
                </div>
            </button>

            {/* Modals */}
            {isFormModalOpen && (
                <Modal title={editingDebt ? "تعديل الدين" : "تسجيل دين جديد"} onClose={() => { setIsFormModalOpen(false); setEditingDebt(undefined); }}>
                    <DebtForm 
                        debt={editingDebt} 
                        onSave={handleSaveForm} 
                        onCancel={() => { setIsFormModalOpen(false); setEditingDebt(undefined); }}
                        contacts={contacts}
                    />
                </Modal>
            )}

            {splittingDebt && (
                <Modal title="جدولة الأقساط" onClose={() => setSplittingDebt(null)}>
                    <SplitDebtModal 
                        debt={splittingDebt} 
                        onCancel={() => setSplittingDebt(null)} 
                        onConfirm={handleSplitDebt} 
                    />
                </Modal>
            )}

            {settlingDebt && (
                <Modal title="تسوية الدين" onClose={() => setSettlingDebt(null)}>
                    <SettleDebtModal 
                        debt={settlingDebt} 
                        accounts={accounts} 
                        onConfirm={handleConfirmSettlement} 
                        onCancel={() => setSettlingDebt(null)}
                    />
                </Modal>
            )}

            {detailsDebt && (
                <Modal title="تفاصيل الدين" onClose={() => setDetailsDebt(null)}>
                    <DebtDetailContent 
                        debt={detailsDebt} 
                        onSelectContact={(id) => { setDetailsDebt(null); onSelectContact(id); }}
                        onClose={() => setDetailsDebt(null)}
                    />
                </Modal>
            )}

            {isFilterModalOpen && (
                <DebtFilterModal 
                    initialFilters={filters}
                    onApply={(newFilters) => { setFilters(newFilters); setIsFilterModalOpen(false); }}
                    onClose={() => setIsFilterModalOpen(false)}
                />
            )}

            <ConfirmDialog 
                isOpen={!!deletingDebt}
                title="حذف الدين"
                message="هل أنت متأكد من حذف هذا الدين؟ لا يمكن التراجع عن هذا الإجراء."
                confirmText="حذف"
                onConfirm={handleDelete}
                onCancel={() => setDeletingDebt(null)}
            />
        </div>
    );
};

export default DebtsPage;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { supabase } from '../lib/supabase';
import { Contact, Debt } from '../types';
import {
    PencilSquareIcon,
    TrashIcon,
    PlusIcon,
    XMarkIcon,
    DocumentArrowDownIcon,
    ArrowRightIcon,
    WalletIcon,
    CalendarDaysIcon,
    CheckCircleIcon,
    SparklesIcon,
    ArrowUpIcon,
    ArrowDownIcon,
    ClockIcon,
    SmartphoneIcon,
    FunnelIcon,
    PrinterIcon,
    WhatsappIcon
} from './icons';

interface ContactProfilePageProps {
    contactId: string;
    onBack: () => void;
    handleDatabaseChange: (description?: string) => void;
}

const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat('ar-LY', {
        style: 'currency',
        currency: 'LYD',
        minimumFractionDigits: 0,
        maximumFractionDigits: 0
    }).format(amount).replace('LYD', 'د.ل');
};

const ContactProfilePage: React.FC<ContactProfilePageProps> = ({ contactId, onBack, handleDatabaseChange }) => {
    const [contact, setContact] = useState<Contact | null>(null);
    const [debts, setDebts] = useState<Debt[]>([]);
    const [loading, setLoading] = useState(true);
    const [activeTab, setActiveTab] = useState<'all' | 'unpaid' | 'paid'>('all');

    // إعدادات التصدير
    const [showExportModal, setShowExportModal] = useState(false);
    const [isExporting, setIsExporting] = useState(false);
    const [exportProgress, setExportProgress] = useState(0);
    const [exportStatus, setExportStatus] = useState('');
    const [pdfFilters, setPdfFilters] = useState({
        type: 'all' as 'all' | 'for_you' | 'on_you',
        status: 'all' as 'all' | 'unpaid' | 'paid'
    });

    const reportRef = useMemo(() => `REF-${Math.floor(1000 + Math.random() * 9000)}`, []);
    const currentDate = useMemo(() => new Date().toLocaleDateString('ar-LY', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' }), []);

    const fetchData = useCallback(async () => {
        setLoading(true);
        try {
            const contactPromise = supabase.from('contacts').select('*').eq('id', contactId).single();
            const debtsPromise = supabase.from('debts').select('*').eq('contact_id', contactId).order('created_at', { ascending: false });

            const [{ data: contactData }, { data: debtsData }] = await Promise.all([contactPromise, debtsPromise]);
            if (contactData) setContact(contactData);
            if (debtsData) setDebts(debtsData as unknown as Debt[]);
        } catch (err) {
            console.error("Error fetching contact data:", err);
        } finally {
            setLoading(false);
        }
    }, [contactId]);

    useEffect(() => { 
        fetchData(); 
    }, [fetchData]);

    const stats = useMemo(() => {
        const forYou = debts.filter(d => d.type === 'for_you' && !d.paid).reduce((sum, d) => sum + d.amount, 0);
        const onYou = debts.filter(d => d.type === 'on_you' && !d.paid).reduce((sum, d) => sum + d.amount, 0);
        return { forYou, onYou, net: forYou - onYou };
    }, [debts]);

    const filteredDebts = useMemo(() => {
        if (activeTab === 'all') return debts;
        if (activeTab === 'unpaid') return debts.filter(d => !d.paid);
        return debts.filter(d => d.paid);
    }, [debts, activeTab]);

    // معالجة البيانات المخصصة للتصدير
    const debtsToPrint = useMemo(() => {
        return debts.filter(d => {
            const typeMatch = pdfFilters.type === 'all' || d.type === pdfFilters.type;
            const statusMatch = pdfFilters.status === 'all' || 
                              (pdfFilters.status === 'paid' && d.paid) || 
                              (pdfFilters.status === 'unpaid' && !d.paid);
            return typeMatch && statusMatch;
        });
    }, [debts, pdfFilters]);

    const printStats = useMemo(() => {
        const forYou = debtsToPrint.filter(d => d.type === 'for_you').reduce((sum, d) => sum + d.amount, 0);
        const onYou = debtsToPrint.filter(d => d.type === 'on_you').reduce((sum, d) => sum + d.amount, 0);
        return { forYou, onYou, net: forYou - onYou };
    }, [debtsToPrint]);

    const handleWhatsAppReminder = (debt: Debt) => {
        if (!contact) return;
        const name = contact.name;
        const amount = formatCurrency(debt.amount);
        const date = debt.due_date ? new Date(debt.due_date).toLocaleDateString('ar-LY') : 'غير محدد';
        const phone = contact.phone || '';

        const message = `مرحباً ${name}، أتمنى أن تكون بخير. أردت فقط إرسال تذكير ودي بخصوص المبلغ المستحق (${amount}) والمقيد بتاريخ ${date}. شكراً لك سلفاً.`;
        const encodedMessage = encodeURIComponent(message);

        window.open(`https://wa.me/${phone.replace(/\+/g, '')}?text=${encodedMessage}`, '_blank');
    };

    const handleExportPDF = async () => {
        setShowExportModal(false);
        setIsExporting(true);
        setExportProgress(0);
        const steps = [
            { p: 30, s: 'جاري تجميع البيانات...' },
            { p: 60, s: 'تنسيق الجدول المالي...' },
            { p: 100, s: 'جاهز للطباعة' }
        ];
        for (const step of steps) {
            setExportStatus(step.s);
            setExportProgress(step.p);
            await new Promise(r => setTimeout(r, 400));
        }
        setTimeout(() => { window.print(); setIsExporting(false); }, 300);
    };

    if (loading) return (
        <div className="flex flex-col items-center justify-center py-32 space-y-4">
            <div className="w-12 h-12 border-4 border-slate-800 border-t-cyan-500 rounded-full animate-spin"></div>
            <p className="text-slate-500 font-bold animate-pulse text-sm">جاري تحميل السجل...</p>
        </div>
    );

    if (!contact) return <div className="p-8 text-center text-rose-400">جهة الاتصال غير موجودة.</div>;

    return (
        <div className="space-y-6 animate-fade-in relative pb-20">
            {/* Navigation Header */}
            <div className="flex justify-between items-center px-1 print:hidden">
                <button onClick={onBack} className="p-2.5 bg-slate-800 text-slate-300 rounded-2xl hover:bg-slate-700 transition active:scale-90">
                    <ArrowRightIcon className="w-6 h-6" />
                </button>
                <button 
                    onClick={() => setShowExportModal(true)} 
                    className="flex items-center gap-2 px-4 py-2.5 bg-cyan-600 text-white rounded-2xl font-black text-sm hover:bg-cyan-500 transition active:scale-95 shadow-lg shadow-cyan-900/20"
                >
                    <DocumentArrowDownIcon className="w-5 h-5" /> تصدير PDF
                </button>
            </div>

            {/* Profile Hero Section */}
            <div className="relative overflow-hidden glass-card rounded-[2.5rem] p-8 border border-white/5 bg-slate-900/40 print:hidden">
                <div className="absolute top-0 right-0 w-40 h-40 bg-cyan-500/10 rounded-full blur-[60px] -translate-y-1/2 translate-x-1/2"></div>

                <div className="flex flex-col items-center text-center relative z-10">
                    <div className="w-24 h-24 bg-gradient-to-tr from-cyan-600 to-blue-700 rounded-[2rem] flex items-center justify-center font-black text-white text-4xl shadow-2xl mb-4 border-4 border-slate-900 ring-1 ring-white/10">
                        {contact.name.charAt(0)}
                    </div>
                    <h2 className="font-black text-3xl text-white mb-1 tracking-tight">{contact.name}</h2>
                    <div className="flex items-center gap-2 text-slate-500 font-bold text-sm mb-8">
                        {contact.phone ? (
                            <><SmartphoneIcon className="w-4 h-4 text-slate-500" /><span className="font-mono">{contact.phone}</span></>
                        ) : 'لا يوجد رقم هاتف'}
                    </div>

                    <div className="w-full">
                        <div className={`p-5 rounded-3xl border transition-all ${stats.net >= 0 ? 'bg-emerald-500/10 border-emerald-500/20' : 'bg-rose-500/10 border-rose-500/20'}`}>
                            <p className="text-[10px] font-black uppercase tracking-widest text-slate-400 mb-1">الرصيد الصافي المستحق</p>
                            <p className={`text-4xl font-black tabular-nums ${stats.net >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                                {formatCurrency(Math.abs(stats.net))}
                                <span className="text-xs font-bold mr-2 opacity-60">{stats.net >= 0 ? '(لك)' : '(عليك)'}</span>
                            </p>
                        </div>
                    </div>
                </div>
            </div>

            {/* Statement Filter Tabs */}
            <div className="flex bg-slate-900/60 p-1 rounded-2xl border border-white/5 print:hidden">
                {(['all', 'unpaid', 'paid'] as const).map(tab => (
                    <button 
                        key={tab} 
                        onClick={() => setActiveTab(tab)} 
                        className={`flex-1 py-3 rounded-xl text-xs font-black transition-all ${activeTab === tab ? 'bg-cyan-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}
                    >
                        {tab === 'all' ? 'الكل' : tab === 'unpaid' ? 'معلقة' : 'تمت'}
                    </button>
                ))}
            </div>

            {/* Transactions List */}
            <div className="space-y-3 print:hidden">
                <div className="flex items-center justify-between px-2 mb-2">
                    <h3 className="text-xs font-black text-slate-500 uppercase tracking-widest flex items-center gap-2">
                        <WalletIcon className="w-4 h-4" /> سجل العمليات المالية
                    </h3>
                    <span className="text-[10px] font-bold text-slate-600">{filteredDebts.length} عملية</span>
                </div>

                {filteredDebts.length > 0 ? (
                    filteredDebts.map(debt => {
                        const isForYou = debt.type === 'for_you';
                        return (
                            <div key={debt.id} className={`group relative p-4 rounded-3xl border transition-all active:scale-[0.98] ${debt.paid ? 'bg-slate-900/30 border-slate-800 opacity-60' : 'bg-slate-800/40 border-white/5'}`}>
                                <div className="flex justify-between items-center">
                                    <div className="flex items-center gap-4">
                                        <div className={`w-11 h-11 rounded-2xl flex items-center justify-center shadow-inner ${debt.paid ? 'bg-slate-800 text-slate-600' : isForYou ? 'bg-emerald-500/10 text-emerald-500' : 'bg-rose-500/10 text-rose-500'}`}>
                                            {debt.paid ? <CheckCircleIcon className="w-6 h-6" /> : isForYou ? <ArrowDownIcon className="w-6 h-6" /> : <ArrowUpIcon className="w-6 h-6" />}
                                        </div>
                                        <div>
                                            <p className="font-bold text-white text-sm line-clamp-1">{debt.description || (isForYou ? 'دين جديد لك' : 'دين جديد عليك')}</p>
                                            <p className="text-[10px] text-slate-500 font-bold flex items-center gap-1 mt-0.5">
                                                <CalendarDaysIcon className="w-3 h-3" />
                                                {new Date(debt.created_at).toLocaleDateString('ar-LY')}
                                            </p>
                                        </div>
                                    </div>
                                    <div className="flex flex-col items-end">
                                        <p className={`text-lg font-black tabular-nums ${debt.paid ? 'text-slate-500 line-through' : isForYou ? 'text-emerald-400' : 'text-rose-400'}`}>
                                            {isForYou ? '+' : '-'}{formatCurrency(debt.amount)}
                                        </p>
                                        {!debt.paid && isForYou && contact.phone && (
                                            <button 
                                                onClick={() => handleWhatsAppReminder(debt)}
                                                className="mt-1 flex items-center gap-1 px-2 py-1 bg-emerald-500/10 text-emerald-500 rounded-lg text-[9px] font-black hover:bg-emerald-500 hover:text-white transition-all"
                                            >
                                                <WhatsappIcon className="w-3 h-3" /> تذكير
                                            </button>
                                        )}
                                    </div>
                                </div>
                            </div>
                        );
                    })
                ) : (
                    <div className="text-center py-20 border-2 border-dashed border-slate-800 rounded-[2.5rem]">
                        <p className="text-slate-600 font-bold text-sm">لا توجد سجلات مطابقة حالياً</p>
                    </div>
                )}
            </div>

            {/* Export Settings Modal */}
            {showExportModal && (
                <div className="fixed inset-0 z-[110] bg-slate-950/95 backdrop-blur-xl flex items-center justify-center p-6 animate-fade-in print:hidden">
                    <div className="w-full max-w-sm bg-slate-900 border border-white/10 rounded-[2.5rem] p-8 space-y-8 animate-slide-up">
                        <div className="flex justify-between items-center">
                            <h3 className="text-xl font-black text-white flex items-center gap-2"><FunnelIcon className="w-6 h-6 text-cyan-500"/> تخصيص الكشف</h3>
                            <button onClick={() => setShowExportModal(false)} className="p-2 bg-white/5 rounded-full text-slate-500 hover:text-white"><XMarkIcon className="w-5 h-5"/></button>
                        </div>

                        <div className="space-y-6">
                            <div className="space-y-3">
                                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest px-1">نوع المعاملات</label>
                                <div className="grid grid-cols-3 gap-2">
                                    {(['all', 'for_you', 'on_you'] as const).map(t => (
                                        <button key={t} onClick={() => setPdfFilters(f => ({...f, type: t}))} className={`py-2.5 rounded-xl text-[10px] font-black border transition-all ${pdfFilters.type === t ? 'bg-cyan-600 text-white border-cyan-500' : 'bg-slate-800 text-slate-500 border-white/5'}`}>
                                            {t === 'all' ? 'الكل' : t === 'for_you' ? 'لك' : 'عليك'}
                                        </button>
                                    ))}
                                </div>
                            </div>

                            <div className="space-y-3">
                                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest px-1">الحالة المالية</label>
                                <div className="grid grid-cols-3 gap-2">
                                    {(['all', 'unpaid', 'paid'] as const).map(s => (
                                        <button key={s} onClick={() => setPdfFilters(f => ({...f, status: s}))} className={`py-2.5 rounded-xl text-[10px] font-black border transition-all ${pdfFilters.status === s ? 'bg-cyan-600 text-white border-cyan-500' : 'bg-slate-800 text-slate-500 border-white/5'}`}>
                                            {s === 'all' ? 'الكل' : s === 'unpaid' ? 'معلقة' : 'تمت'}
                                        </button>
                                    ))}
                                </div>
                            </div>
                        </div>

                        <button 
                            onClick={handleExportPDF} 
                            className="w-full py-4 bg-cyan-600 text-white rounded-2xl font-black text-lg shadow-xl shadow-cyan-900/30 active:scale-95 flex items-center justify-center gap-3 transition-transform"
                        >
                            <PrinterIcon className="w-6 h-6" /> توليد الكشف PDF
                        </button>
                    </div>
                </div>
            )}

            {/* Exporting Progress Modal */}
            {isExporting && (
                <div className="fixed inset-0 z-[120] bg-slate-950/90 backdrop-blur-xl flex items-center justify-center p-6 animate-fade-in print:hidden">
                    <div className="w-full max-w-xs space-y-8 text-center">
                        <div className="relative w-24 h-24 mx-auto">
                            <div className="absolute inset-0 border-4 border-slate-800 rounded-full"></div>
                            <div className="absolute inset-0 flex items-center justify-center">
                                <SparklesIcon className="w-10 h-10 text-cyan-400 animate-pulse" />
                            </div>
                        </div>
                        <div className="space-y-2">
                            <h3 className="text-xl font-black text-white">جاري إنشاء الكشف</h3>
                            <p className="text-slate-400 text-sm font-bold">{exportStatus}</p>
                        </div>
                    </div>
                </div>
            )}

            {/* --- PRINT TEMPLATE (PROFESSIONAL TABLE LAYOUT) --- */}
            <div className="print-only bg-white text-black p-10 font-sans min-h-screen relative" dir="rtl">
                {/* PDF Header */}
                <div className="flex justify-between items-start border-b-4 border-slate-900 pb-8 mb-8">
                    <div>
                        <h1 className="text-3xl font-black text-slate-900 mb-1">كشف حساب مالي</h1>
                        <p className="text-slate-500 font-bold text-xs uppercase tracking-widest">محفظتي الإلكترونية الذكية</p>
                        <div className="mt-4 flex items-center gap-2 text-sm font-black text-slate-800">
                             <CalendarDaysIcon className="w-4 h-4" /> 
                             {currentDate}
                        </div>
                    </div>
                    <div className="text-left">
                        <p className="text-[9px] font-black text-slate-400 uppercase mb-1">الرقم المرجعي</p>
                        <p className="font-mono text-xs font-black bg-slate-100 px-3 py-1 rounded border border-slate-200">{reportRef}</p>
                    </div>
                </div>

                {/* Info Section */}
                <div className="grid grid-cols-2 gap-10 mb-10">
                    <div className="bg-slate-50 p-6 rounded-2xl border border-slate-200">
                        <h4 className="text-[10px] font-black text-slate-400 uppercase mb-3">جهة الاتصال</h4>
                        <p className="text-2xl font-black text-slate-900">{contact.name}</p>
                        <p className="text-slate-600 font-bold text-sm mt-1">{contact.phone || 'بدون هاتف'}</p>
                    </div>
                    <div className="bg-slate-900 p-6 rounded-2xl text-white shadow-xl flex flex-col justify-center">
                        <h4 className="text-[10px] text-white/40 font-black uppercase mb-2">صافي الرصيد المستحق للكشف</h4>
                        <p className="text-4xl font-black tabular-nums">{formatCurrency(Math.abs(stats.net))}</p>
                        <p className={`text-xs font-bold mt-2 ${stats.net >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                            {stats.net >= 0 ? 'رصيد دائن (مستحق لك)' : 'رصيد مدين (مستحق عليك)'}
                        </p>
                    </div>
                </div>

                {/* Totals Summary */}
                <div className="grid grid-cols-2 gap-4 mb-8">
                    <div className="border border-slate-200 rounded-xl p-4 bg-emerald-50/30 flex justify-between items-center">
                        <span className="text-xs font-bold text-slate-600">إجمالي لك (+)</span>
                        <span className="text-lg font-black text-emerald-700">{formatCurrency(printStats.forYou)}</span>
                    </div>
                    <div className="border border-slate-200 rounded-xl p-4 bg-rose-50/30 flex justify-between items-center">
                        <span className="text-xs font-bold text-slate-600">إجمالي عليك (-)</span>
                        <span className="text-lg font-black text-rose-700">{formatCurrency(printStats.onYou)}</span>
                    </div>
                </div>

                {/* Professional Data Table */}
                <div className="mb-10">
                    <table className="w-full border-collapse">
                        <thead>
                            <tr className="bg-slate-900 text-white text-xs uppercase tracking-wider">
                                <th className="p-3 text-right border-slate-700 w-10">#</th>
                                <th className="p-3 text-right border-slate-700">التاريخ</th>
                                <th className="p-3 text-right border-slate-700">البيان والتفاصيل</th>
                                <th className="p-3 text-center border-slate-700">النوع</th>
                                <th className="p-3 text-center border-slate-700">الحالة</th>
                                <th className="p-3 text-left border-slate-700">المبلغ</th>
                            </tr>
                        </thead>
                        <tbody>
                            {debtsToPrint.map((d, i) => (
                                <tr key={d.id} className={`text-xs ${i % 2 === 0 ? 'bg-white' : 'bg-slate-50'} border-b border-slate-100`}>
                                    <td className="p-3 text-slate-400 font-mono">{i + 1}</td>
                                    <td className="p-3 text-slate-600 font-mono">{new Date(d.created_at).toLocaleDateString('ar-LY')}</td>
                                    <td className="p-3 font-bold text-slate-800">{d.description || 'عملية مالية مسجلة'}</td>
                                    <td className="p-3 text-center">
                                        <span className={`px-2 py-0.5 rounded-full font-black text-[9px] ${d.type === 'for_you' ? 'bg-emerald-100 text-emerald-800' : 'bg-rose-100 text-rose-800'}`}>
                                            {d.type === 'for_you' ? 'دائن (+)' : 'مدين (-)'}
                                        </span>
                                    </td>
                                    <td className="p-3 text-center">
                                        <span className={`font-bold ${d.paid ? 'text-slate-400' : 'text-amber-600'}`}>
                                            {d.paid ? 'تم التسوية' : 'معلّق'}
                                        </span>
                                    </td>
                                    <td className={`p-3 text-left font-black text-sm tabular-nums font-mono ${d.type === 'for_you' ? 'text-emerald-700' : 'text-rose-700'}`}>
                                        {d.type === 'for_you' ? '+' : '-'}{formatCurrency(d.amount)}
                                    </td>
                                </tr>
                            ))}
                            {debtsToPrint.length === 0 && (
                                <tr>
                                    <td colSpan={6} className="p-10 text-center text-slate-400 font-bold italic">لا توجد سجلات مطابقة لهذه الفلاتر</td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>

                {/* Footer Section */}
                <div className="mt-auto pt-10 border-t-2 border-slate-100">
                    <div className="flex justify-between items-end">
                        <div className="text-slate-400 text-[9px] font-bold space-y-1">
                            <p>تم استخراج هذا التقرير بتاريخ: {new Date().toLocaleString('ar-LY')}</p>
                            <p>تطبيق محفظتي الإلكترونية - جميع العمليات خاضعة لتدقيق المستخدم.</p>
                            <p className="text-slate-900 font-black pt-3 text-[11px] tracking-widest uppercase">By GreenBox 2025</p>
                        </div>
                        <div className="text-center">
                            <div className="w-40 h-px bg-slate-900 mb-2 mx-auto"></div>
                            <p className="text-[10px] font-black text-slate-900 uppercase">توقيع المصادقة</p>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default ContactProfilePage;

// Fix: Define the Page type as a union of string literals to avoid circular dependency.
export type Page = 'home' | 'accounts' | 'transactions' | 'debts' | 'contacts' | 'categories' | 'reports' | 'notes' | 'investments' | 'goals';

// From user prompt:
// accounts: id(uuid), name(text), type(text), balance(numeric), currency(text)
export interface Account {
  id: string;
  name: string;
  type: string; // "نقدي", "بنكي", "مخصص"
  balance: number;
  currency: string;
  theme?: string; 
  card_pattern?: string;
  custom_icon?: string;
  // Added properties to match the new professional UI styles
  style_preset?: string;
  pattern_type?: string;
}

// transactions: id(uuid), account_id(uuid), amount(numeric), date(timestamptz), category_id(uuid), type(text), notes(text), to_account_id(uuid)
export interface Transaction {
  id: string;
  account_id: string | null;
  amount: number;
  date: string; // ISO string
  category_id: string | null;
  type: 'income' | 'expense' | 'transfer';
  notes: string | null;
  to_account_id: string | null;
  created_at?: string;
  // For display purposes after joining
  accounts?: { name: string; currency: string } | null;
  // Fix: Add optional color and icon to categories to match more detailed queries.
  categories?: { name: string; color?: string | null; icon?: string | null; } | null;
  to_accounts?: { name: string } | null;
}

// contacts: id(uuid), name(text), phone(text), address(text)
export interface Contact {
  id: string;
  name: string;
  phone: string | null;
  address: string | null;
}

// debts: id(uuid), contact_id(uuid), amount(numeric), due_date(date), paid(boolean), type('for_you' | 'on_you'), description(text), linked_transaction_id(uuid), created_at(timestamptz), paid_at(timestamptz)
export interface Debt {
  id: string;
  contact_id: string | null;
  amount: number;
  due_date: string | null; // Date string
  paid: boolean;
  paid_at: string | null;
  type: 'for_you' | 'on_you';
  description: string | null;
  linked_transaction_id: string | null;
  created_at: string;
  account_id: string | null;
  // For display
  // Fix: Added optional phone property to contacts join to support features like WhatsApp reminders
  contacts?: { name: string; phone?: string | null } | null;
  accounts?: { name: string } | null;
}

// categories: id(uuid), name(text), color(text), icon(text), type('income' | 'expense')
export interface Category {
  id: string;
  name: string;
  color: string | null;
  icon: string | null;
  type: 'income' | 'expense';
}

// notes: id(uuid), note_text(text), color(varchar), is_pinned(bool), is_code(bool), language(varchar), created_at(timestamptz), updated_at(timestamptz)
export interface Note {
  id: string;
  note_text: string;
  color: string;
  is_pinned: boolean;
  is_code: boolean;
  language: string | null;
  created_at: string;
  updated_at: string;
}

// investments: id(uuid), name(text), amount(numeric), type(text), current_value(numeric), created_at(timestamptz)
export interface Investment {
  id: string;
  name: string;
  type: string; // "ذهب", "أسهم", "عملات", "مدخرات"
  amount: number; // Purchase price
  current_value: number;
  created_at: string;
}

// goals: id(uuid), name(text), target_amount(numeric), current_amount(numeric), deadline(date), color(text), icon(text)
export interface Goal {
  id: string;
  name: string;
  target_amount: number;
  current_amount: number;
  deadline: string | null;
  color: string;
  icon: string;
  created_at: string;
}

// Fix: Define the Page type as a union of string literals to avoid circular dependency.
export type Page = 'home' | 'accounts' | 'transactions' | 'debts' | 'contacts' | 'categories' | 'reports' | 'notes' | 'investments' | 'goals' | 'tools';

// From user prompt:
// accounts: id(uuid), name(text), type(text), balance(numeric), currency(text)
export interface Account {
  id: string;
  name: string;
  type: string; // "نقدي", "بنكي", "مخصص"
  balance: number;
  currency: string;
  theme?: string; 
  card_pattern?: string;
  custom_icon?: string;
  // Added properties to match the new professional UI styles
  style_preset?: string;
  pattern_type?: string;
}

// transactions: id(uuid), account_id(uuid), amount(numeric), date(timestamptz), category_id(uuid), type(text), notes(text), to_account_id(uuid)
export interface Transaction {
  id: string;
  account_id: string | null;
  amount: number;
  date: string; // ISO string
  category_id: string | null;
  type: 'income' | 'expense' | 'transfer';
  notes: string | null;
  to_account_id: string | null;
  created_at?: string;
  // For display purposes after joining
  accounts?: { name: string; currency: string } | null;
  // Fix: Add optional color and icon to categories to match more detailed queries.
  categories?: { name: string; color?: string | null; icon?: string | null; } | null;
  to_accounts?: { name: string } | null;
}

// contacts: id(uuid), name(text), phone(text), address(text)
export interface Contact {
  id: string;
  name: string;
  phone: string | null;
  address: string | null;
}

// debts: id(uuid), contact_id(uuid), amount(numeric), due_date(date), paid(boolean), type('for_you' | 'on_you'), description(text), linked_transaction_id(uuid), created_at(timestamptz), paid_at(timestamptz)
export interface Debt {
  id: string;
  contact_id: string | null;
  amount: number;
  due_date: string | null; // Date string
  paid: boolean;
  paid_at: string | null;
  type: 'for_you' | 'on_you';
  description: string | null;
  linked_transaction_id: string | null;
  created_at: string;
  account_id: string | null;
  // For display
  // Fix: Added optional phone property to contacts join to support features like WhatsApp reminders
  contacts?: { name: string; phone?: string | null } | null;
  accounts?: { name: string } | null;
}

// categories: id(uuid), name(text), color(text), icon(text), type('income' | 'expense')
export interface Category {
  id: string;
  name: string;
  color: string | null;
  icon: string | null;
  type: 'income' | 'expense';
}

// notes: id(uuid), note_text(text), color(varchar), is_pinned(bool), is_code(bool), language(varchar), created_at(timestamptz), updated_at(timestamptz)
export interface Note {
  id: string;
  note_text: string;
  color: string;
  is_pinned: boolean;
  is_code: boolean;
  language: string | null;
  created_at: string;
  updated_at: string;
}

// investments: id(uuid), name(text), amount(numeric), type(text), current_value(numeric), created_at(timestamptz)
export interface Investment {
  id: string;
  name: string;
  type: string; // "ذهب", "أسهم", "عملات", "مدخرات"
  amount: number; // Purchase price
  current_value: number;
  created_at: string;
}

// goals: id(uuid), name(text), target_amount(numeric), current_amount(numeric), deadline(date), color(text), icon(text)
export interface Goal {
  id: string;
  name: string;
  target_amount: number;
  current_amount: number;
  deadline: string | null;
  color: string;
  icon: string;
  created_at: string;
}

