                </div>
            ) : (
                <>
                    {/* Calendar Grid */}
                    <div className="grid grid-cols-7 gap-1.5 mb-8">
                        {dayNames.map(d => (
                            <div key={d} className="text-center text-[9px] font-black text-slate-600 pb-2 uppercase">{d}</div>
                        ))}
                        {calendarGrid.map((day, idx) => {
