import React, { useState, useEffect } from 'react';
import { Page, Debt } from './types';
import Header from './components/Header';
import Sidebar from './components/Sidebar';
import HomePage from './components/HomePage';
import AccountsPage from './components/AccountsPage';
import TransactionsPage from './components/TransactionsPage';
import DebtsPage from './components/DebtsPage';
import ContactsPage from './components/ContactsPage';
import ContactProfilePage from './components/ContactProfilePage';
import CategoriesPage from './components/CategoriesPage';
import ReportsPage from './components/ReportsPage';
import NotesPage from './components/NotesPage';
import InvestmentsPage from './components/InvestmentsPage';
import SavingsGoalsPage from './components/SavingsGoalsPage';
import ToolsPage from './components/ToolsPage';
import BudgetsPage from './components/BudgetsPage';
import AssetsPage from './components/AssetsPage';
import ShoppingListPage from './components/ShoppingListPage';
import RecurringTransactionsPage from './components/RecurringTransactionsPage';
import BottomNav from './components/BottomNav';
import { ToastProvider } from './components/Toast';
import { supabase } from './lib/supabase';
import { WalletIcon } from './components/icons';
import { QueryClient, QueryClientProvider, useQuery } from '@tanstack/react-query';

// Create a client
const queryClient = new QueryClient({
  defaultOptions: {
    queries: {
      staleTime: 1000 * 60 * 5, 
      gcTime: 1000 * 60 * 60, 
      refetchOnWindowFocus: false,
    },
  },
});

function AppContent() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [passwordInput, setPasswordInput] = useState('');
  const [authError, setAuthError] = useState('');

  const [activePage, setActivePage] = useState<Page>('home');
  const [isSidebarOpen, setSidebarOpen] = useState(false);
  const [isStealthMode, setIsStealthMode] = useState(false);
  const [refreshTrigger, setRefreshTrigger] = useState(0);
  const [activeContactId, setActiveContactId] = useState<string | null>(null);
  const [activeContactName, setActiveContactName] = useState<string>('');

  useEffect(() => {
    if (localStorage.getItem('app_authenticated') === 'true') setIsAuthenticated(true);
    if (localStorage.getItem('stealth_mode') === 'true') setIsStealthMode(true);
  }, []);

  const toggleStealthMode = () => {
    const newVal = !isStealthMode;
    setIsStealthMode(newVal);
    localStorage.setItem('stealth_mode', newVal.toString());
  };

  const handlePasswordSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (passwordInput === '9991') {
      localStorage.setItem('app_authenticated', 'true');
      setIsAuthenticated(true);
      setAuthError('');
    } else {
      setAuthError('كلمة المرور غير صحيحة');
      setPasswordInput('');
    }
  };

  const handleDatabaseChange = (description?: string) => {
      setRefreshTrigger(prev => prev + 1);
      queryClient.invalidateQueries();
  };

  const { data: debtNotifications = [] } = useQuery<Debt[]>({
    queryKey: ['debtNotifications', refreshTrigger],
    queryFn: async () => {
        const { data: debtData } = await supabase.from('debts').select('*, contacts(name)').eq('paid', false).not('due_date', 'is', null);
        if (!debtData) return [];
        const today = new Date(); today.setHours(0,0,0,0);
        const soon = new Date(); soon.setDate(today.getDate() + 7);
        return (debtData as unknown as Debt[]).filter(d => {
            const due = new Date(d.due_date!);
            return due < soon;
        });
    },
    enabled: isAuthenticated,
    refetchInterval: 60000,
  });

  const handleSelectContact = async (contactId: string) => {
    setActiveContactId(contactId);
    try {
        const { data } = await supabase.from('contacts').select('name').eq('id', contactId).single();
        setActiveContactName(data?.name || 'ملف شخصي');
        setActivePage('contacts');
    } catch(e) {
        setActiveContactName('ملف شخصي');
        setActivePage('contacts');
    }
  };

  const handleBackToContacts = () => {
    setActiveContactId(null);
    setActiveContactName('');
    setActivePage('contacts');
  };

  const renderPage = () => {
    if (activePage === 'contacts' && activeContactId) {
        return <ContactProfilePage contactId={activeContactId} onBack={handleBackToContacts} handleDatabaseChange={handleDatabaseChange} />;
    }

    switch (activePage) {
      case 'home': return <HomePage refreshTrigger={refreshTrigger} handleDatabaseChange={handleDatabaseChange} setActivePage={setActivePage} />;
      case 'accounts': return <AccountsPage refreshTrigger={refreshTrigger} handleDatabaseChange={handleDatabaseChange} />;
      case 'transactions': return <TransactionsPage />;
      case 'debts': return <DebtsPage refreshTrigger={refreshTrigger} handleDatabaseChange={handleDatabaseChange} onSelectContact={handleSelectContact} />;
      case 'contacts': return <ContactsPage refreshTrigger={refreshTrigger} handleDatabaseChange={handleDatabaseChange} onSelectContact={handleSelectContact} />;
      case 'categories': return <CategoriesPage refreshTrigger={refreshTrigger} handleDatabaseChange={handleDatabaseChange} />;
      case 'reports': return <ReportsPage refreshTrigger={refreshTrigger} />;
      case 'notes': return <NotesPage refreshTrigger={refreshTrigger} handleDatabaseChange={handleDatabaseChange} />;
      case 'investments': return <InvestmentsPage refreshTrigger={refreshTrigger} handleDatabaseChange={handleDatabaseChange} />;
      case 'goals': return <SavingsGoalsPage refreshTrigger={refreshTrigger} handleDatabaseChange={handleDatabaseChange} />;
      case 'budgets': return <BudgetsPage refreshTrigger={refreshTrigger} />;
      case 'assets': return <AssetsPage refreshTrigger={refreshTrigger} />;
      case 'shopping': return <ShoppingListPage refreshTrigger={refreshTrigger} handleDatabaseChange={handleDatabaseChange} />;
      case 'recurring': return <RecurringTransactionsPage refreshTrigger={refreshTrigger} />;
      case 'tools': return <ToolsPage isStealthMode={isStealthMode} toggleStealthMode={toggleStealthMode} handleDatabaseChange={handleDatabaseChange} />;
      default: return <HomePage refreshTrigger={refreshTrigger} handleDatabaseChange={handleDatabaseChange} setActivePage={setActivePage} />;
    }
  };

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen font-sans flex items-center justify-center p-4 relative overflow-hidden" dir="rtl">
        <div className="glass-card w-full max-sm p-8 rounded-3xl shadow-2xl text-center animate-slide-up relative z-10">
          <div className="w-20 h-20 bg-gradient-to-br from-cyan-400 to-blue-600 rounded-2xl mx-auto mb-8 flex items-center justify-center shadow-lg shadow-cyan-500/30 rotate-3">
             <WalletIcon className="w-10 h-10 text-white" />
          </div>
          <h1 className="text-3xl font-bold text-white mb-2 tracking-tight">أهلاً بعودتك</h1>
          <form onSubmit={handlePasswordSubmit} className="space-y-6">
            <input type="password" value={passwordInput} onChange={(e) => setPasswordInput(e.target.value)} className="w-full bg-slate-950/50 border border-slate-700/50 rounded-2xl p-4 text-white text-center text-2xl tracking-[0.5em] focus:outline-none" placeholder="••••" autoFocus />
            {authError && <p className="text-rose-400 text-sm">{authError}</p>}
            <button type="submit" className="w-full bg-gradient-to-r from-cyan-500 to-blue-600 text-white font-bold py-4 rounded-2xl shadow-lg">دخول</button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className={`min-h-screen font-sans pb-24 md:pb-0 lg:flex lg:flex-row-reverse ${isStealthMode ? 'stealth-active' : ''}`} dir="rtl">
        <style>{`.stealth-active .tabular-nums, .stealth-active .text-4xl, .stealth-active .text-3xl, .stealth-active .text-5xl, .stealth-active .font-extrabold { filter: blur(8px); pointer-events: none; user-select: none; }`}</style>
        <Sidebar isOpen={isSidebarOpen} onClose={() => setSidebarOpen(false)} activePage={activePage} setActivePage={setActivePage} />
        <div className="flex-1 lg:mr-80">
            <Header activePage={activePage} onMenuClick={() => setSidebarOpen(true)} isProfilePage={!!activeContactId} profileName={activeContactName} onBack={handleBackToContacts} notifications={debtNotifications} onNavigate={(page) => setActivePage(page)} />
            <main className="max-w-7xl mx-auto p-4 md:p-6 lg:p-8 animate-fade-in">{renderPage()}</main>
        </div>
        <BottomNav activePage={activePage} setActivePage={setActivePage} debtNotificationCount={debtNotifications.length} />
    </div>
  );
}

function App() {
    return (
        <QueryClientProvider client={queryClient}>
            <ToastProvider>
                <AppContent />
            </ToastProvider>
        </QueryClientProvider>
    )
}

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { supabase } from '../lib/supabase';
import { Budget, Category, Transaction } from '../types';
import { PlusIcon, XMarkIcon, ChartPieIcon, TrashIcon, iconMap, TagIcon } from './icons';
import { useToast } from './Toast';

const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat('ar-LY', { style: 'currency', currency: 'LYD', minimumFractionDigits: 0 }).format(amount).replace('LYD', 'د.ل');
};

const BudgetsPage: React.FC<{ refreshTrigger?: number }> = ({ refreshTrigger }) => {
    const [budgets, setBudgets] = useState<Budget[]>([]);
    const [categories, setCategories] = useState<Category[]>([]);
    const [expenses, setExpenses] = useState<Transaction[]>([]);
    const [loading, setLoading] = useState(true);
    const [showAddModal, setShowAddModal] = useState(false);
    const toast = useToast();

    // Form state
    const [selectedCat, setSelectedCat] = useState('');
    const [limit, setLimit] = useState('');

    const fetchData = async () => {
        setLoading(true);
        const now = new Date();
        const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1).toISOString();

        const [budRes, catRes, expRes] = await Promise.all([
            supabase.from('budgets').select('*, categories(*)'),
            supabase.from('categories').select('*').eq('type', 'expense'),
            supabase.from('transactions').select('amount, category_id').eq('type', 'expense').gte('date', startOfMonth)
        ]);

        setBudgets(budRes.data || []);
        setCategories(catRes.data || []);
        setExpenses(expRes.data || []);
        setLoading(false);
    };

    useEffect(() => { fetchData(); }, [refreshTrigger]);

    const budgetStats = useMemo(() => {
        return budgets.map(b => {
            const spent = expenses.filter(e => e.category_id === b.category_id).reduce((s, e) => s + e.amount, 0);
            return { ...b, spent, percentage: (spent / b.amount_limit) * 100 };
        });
    }, [budgets, expenses]);

    const handleAddBudget = async (e: React.FormEvent) => {
        e.preventDefault();
        const { error } = await supabase.from('budgets').insert({
            category_id: selectedCat,
            amount_limit: Number(limit)
        });
        if (!error) {
            toast.success('تمت إضافة الميزانية');
            setShowAddModal(false);
            fetchData();
        }
    };

    const handleDelete = async (id: string) => {
        const { error } = await supabase.from('budgets').delete().eq('id', id);
        if (!error) {
            toast.success('تم الحذف');
            fetchData();
        }
    };

    return (
        <div className="space-y-6 pb-20">
            <div className="flex justify-between items-center">
                <h2 className="text-xl font-black text-white flex items-center gap-3">
                    <ChartPieIcon className="w-7 h-7 text-cyan-500" /> ميزانيات الفئات
                </h2>
                <button onClick={() => setShowAddModal(true)} className="p-3 bg-cyan-600 text-white rounded-xl shadow-lg active:scale-95 transition-all">
                    <PlusIcon className="w-5 h-5" />
                </button>
            </div>

            {loading ? <div className="h-40 bg-slate-800 animate-pulse rounded-3xl"></div> : (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {budgetStats.length === 0 ? (
                        <div className="col-span-full py-20 text-center bg-slate-900/40 rounded-[2rem] border-2 border-dashed border-slate-800 text-slate-500 font-bold">
                            لم تقم بتعيين حدود صرف للفئات بعد.
                        </div>
                    ) : budgetStats.map(b => {
                        const Icon = (b.categories?.icon && iconMap[b.categories.icon]) ? iconMap[b.categories.icon] : TagIcon;
                        const isExceeded = b.spent > b.amount_limit;
                        return (
                            <div key={b.id} className="glass-card p-6 rounded-3xl border border-white/5 relative overflow-hidden">
                                <div className="flex justify-between items-start mb-4">
                                    <div className="flex items-center gap-3">
                                        <div className="w-12 h-12 rounded-2xl flex items-center justify-center text-white" style={{ backgroundColor: b.categories?.color }}>
                                            <Icon className="w-6 h-6" />
                                        </div>
                                        <div>
                                            <h3 className="font-bold text-white text-lg">{b.categories?.name}</h3>
                                            <p className="text-[10px] text-slate-500 font-black">ميزانية شهرية</p>
                                        </div>
                                    </div>
                                    <button onClick={() => handleDelete(b.id)} className="text-slate-600 hover:text-rose-500"><TrashIcon className="w-5 h-5"/></button>
                                </div>
                                <div className="space-y-3">
                                    <div className="flex justify-between text-sm">
                                        <span className="text-slate-400 font-bold">المصروف: {formatCurrency(b.spent)}</span>
                                        <span className={`font-black ${isExceeded ? 'text-rose-500' : 'text-emerald-400'}`}>{b.percentage.toFixed(0)}%</span>
                                    </div>
                                    <div className="h-3 bg-slate-800 rounded-full overflow-hidden p-0.5 border border-white/5">
                                        <div 
                                            className={`h-full rounded-full transition-all duration-1000 ${isExceeded ? 'bg-rose-500 shadow-[0_0_10px_rgba(244,63,94,0.5)]' : 'bg-cyan-500'}`}
                                            style={{ width: `${Math.min(b.percentage, 100)}%` }}
                                        ></div>
                                    </div>
                                    <div className="flex justify-between text-[10px] font-black text-slate-500">
                                        <span>باقي: {formatCurrency(Math.max(0, b.amount_limit - b.spent))}</span>
                                        <span>الحد: {formatCurrency(b.amount_limit)}</span>
                                    </div>
                                </div>
                            </div>
                        );
                    })}
                </div>
            )}

            {showAddModal && (
                <div className="fixed inset-0 z-50 bg-slate-950/90 flex items-center justify-center p-4 animate-fade-in">
                    <div className="glass-card bg-slate-900 w-full max-w-md p-6 rounded-[2.5rem] border border-white/10 animate-slide-up">
                        <div className="flex justify-between items-center mb-6">
                            <h3 className="text-xl font-bold text-white">تحديد سقف صرف</h3>
                            <button onClick={() => setShowAddModal(false)}><XMarkIcon className="w-6 h-6 text-slate-500"/></button>
                        </div>
                        <form onSubmit={handleAddBudget} className="space-y-6">
                            <div>
                                <label className="text-xs text-slate-500 font-bold block mb-2">الفئة</label>
                                <select value={selectedCat} onChange={e => setSelectedCat(e.target.value)} required className="w-full bg-slate-800 border border-slate-700 rounded-xl p-4 text-white focus:outline-none">
                                    <option value="">اختر فئة...</option>
                                    {categories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                                </select>
                            </div>
                            <div>
                                <label className="text-xs text-slate-500 font-bold block mb-2">الحد الأقصى للمصروفات</label>
                                <input type="number" value={limit} onChange={e => setLimit(e.target.value)} required placeholder="0.00" className="w-full bg-slate-800 border border-slate-700 rounded-xl p-4 text-white text-center text-3xl font-black focus:outline-none" />
                            </div>
                            <button type="submit" className="w-full py-4 bg-cyan-600 text-white rounded-2xl font-bold active:scale-95 transition-all shadow-xl">تأكيد الميزانية</button>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
};

