const PartialPaymentModal: React.FC<{ debt: Debt, accounts: Account[], onSuccess: () => void, onCancel: () => void }> = ({ debt, accounts, onSuccess, onCancel }) => {
    const [amount, setAmount] = useState('');
    const [accId, setAccId] = useState(accounts[0]?.id || '');
    const [isSaving, setIsSaving] = useState(false);
    const toast = useToast();

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        const payAmount = Number(amount);
        if (payAmount <= 0 || payAmount > debt.amount) return toast.error('مبلغ غير صحيح');

        setIsSaving(true);
        // 1. Record payment
        await supabase.from('debt_payments').insert({
            debt_id: debt.id, amount: payAmount, account_id: accId
        });

        // 2. Update Account
        const { data: acc } = await supabase.from('accounts').select('balance').eq('id', accId).single();
        if (acc) {
            const sign = debt.type === 'on_you' ? -1 : 1;
            await supabase.from('accounts').update({ balance: acc.balance + (payAmount * sign) }).eq('id', accId);
        }

        // 3. Update Debt remaining amount
        const newTotal = debt.amount - payAmount;
        if (newTotal <= 0) {
            await supabase.from('debts').update({ amount: 0, paid: true, paid_at: new Date().toISOString() }).eq('id', debt.id);
        } else {
            await supabase.from('debts').update({ amount: newTotal }).eq('id', debt.id);
        }

        // 4. Transaction log
        await supabase.from('transactions').insert({
            amount: payAmount, type: debt.type === 'on_you' ? 'expense' : 'income', 
            account_id: accId, notes: `دفعة جزء من دين: ${debt.description || 'بدون وصف'}`, date: new Date().toISOString()
        });

        logActivity(`تسديد جزئي بقيمة ${formatCurrency(payAmount)} لـ ${debt.contacts?.name}`);
        onSuccess();
        setIsSaving(false);
    };

    return (
        <form onSubmit={handleSubmit} className="space-y-6">
            <div className="text-center">
                <p className="text-[10px] text-slate-500 font-black mb-1 uppercase">المبلغ المدفوع حالياً</p>
                <input type="number" step="0.01" value={amount} onChange={e => setAmount(e.target.value)} required autoFocus placeholder="0.00" className="w-full bg-transparent text-center text-5xl font-black text-cyan-400 focus:outline-none" />
            </div>
            <div>
                <label className="text-xs font-bold text-slate-500 block mb-2 px-1">استخدام حساب</label>
                <select value={accId} onChange={e => setAccId(e.target.value)} required className="w-full bg-slate-800 border border-slate-700 rounded-xl p-4 text-white">
                    {accounts.map(a => <option key={a.id} value={a.id}>{a.name} ({formatCurrency(a.balance)})</option>)}
                </select>
            </div>
            <button type="submit" disabled={isSaving} className="w-full py-4 bg-cyan-600 text-white rounded-2xl font-bold shadow-xl shadow-cyan-900/20 active:scale-95 transition-all">تأكيد الدفعة</button>
        </form>
    );
};

