                    </>
                ) : (
                    <div className="w-full py-2 bg-slate-800/50 rounded-xl text-center text-[11px] font-black text-slate-500 flex items-center justify-center gap-2">
                        <CheckCircleIcon className="w-4 h-4" /> تم التسديد بالكامل
