                    <button onClick={() => setShowHistory(!showHistory)} className="p-3 bg-white/5 text-slate-400 rounded-xl hover:text-white transition-colors">
                        {showHistory ? <ChevronUpIcon className="w-5 h-5" /> : <ChevronDownIcon className="w-5 h-5" />}
                    </button>
                )}
            </div>

            {/* Payments History (Installments) */}
            {showHistory && debt.payments && (
                <div className="mt-4 space-y-2 animate-fade-in">
                    <p className="text-[10px] font-black text-slate-600 uppercase tracking-widest px-2">سجل الأقساط المسددة</p>
