            <div className="grid grid-cols-2 gap-4">
                <button onClick={() => setActiveTab('for_you')} className={`p-6 rounded-[2rem] border transition-all relative overflow-hidden ${activeTab === 'for_you' ? 'bg-emerald-500/10 border-emerald-500/50 shadow-xl' : 'bg-slate-900/50 border-white/5 opacity-60'}`}>
                    {activeTab === 'for_you' && <div className="absolute top-0 right-0 w-20 h-20 bg-emerald-500/10 blur-2xl rounded-full"></div>}
                    <p className="text-[11px] font-black text-slate-500 uppercase mb-2 flex items-center gap-2"><ArrowDownIcon className="w-4 h-4" /> ديون لك</p>
                    <p className="text-2xl font-black text-white tabular-nums">{formatCurrency(stats.forYou)}</p>
                </button>
                <button onClick={() => setActiveTab('on_you')} className={`p-6 rounded-[2rem] border transition-all relative overflow-hidden ${activeTab === 'on_you' ? 'bg-rose-500/10 border-rose-500/50 shadow-xl' : 'bg-slate-900/50 border-white/5 opacity-60'}`}>
                    {activeTab === 'on_you' && <div className="absolute top-0 right-0 w-20 h-20 bg-rose-500/10 blur-2xl rounded-full"></div>}
                    <p className="text-[11px] font-black text-slate-500 uppercase mb-2 flex items-center gap-2"><ArrowUpIcon className="w-4 h-4" /> ديون عليك</p>
                    <p className="text-2xl font-black text-white tabular-nums">{formatCurrency(stats.onYou)}</p>
                </button>
            </div>

            {loading ? (
                <div className="space-y-4">
                    {[1, 2, 3].map(i => <div key={i} className="h-32 bg-slate-800/40 rounded-[2rem] animate-pulse"></div>)}
                </div>
            ) : (
                <div className="space-y-4">
                    {debts.filter(d => d.type === activeTab).length === 0 ? (
                        <div className="py-20 text-center glass-card rounded-[2.5rem] border-2 border-dashed border-slate-800">
                            <p className="text-slate-600 font-bold">لا يوجد سجلات في هذا القسم حالياً</p>
                        </div>
                    ) : (
                        debts.filter(d => d.type === activeTab).map(debt => (
                            <DebtItem 
                                key={debt.id} 
                                debt={debt} 
                                onPartialPay={setPartialPayDebt} 
                                onSelectContact={onSelectContact} 
                            />
                        ))
                    )}
                </div>
            )}

            {partialPayDebt && (
                <Modal title="تسديد قسط من الدين" onClose={() => setPartialPayDebt(null)}>
                    <PartialPaymentModal 
                        debt={partialPayDebt} 
                        accounts={accounts} 
                        onSuccess={() => { setPartialPayDebt(null); handleDatabaseChange(); fetchData(); }} 
                        onCancel={() => setPartialPayDebt(null)} 
                    />
                </Modal>
            )}
        </div>
    );
};

export default DebtsPage;

