import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { supabase } from '../lib/supabase';
import { Debt, Contact, Account, DebtPayment } from '../types';
import { useToast } from './Toast';
import ConfirmDialog from './ConfirmDialog';
import { 
    PlusIcon, PencilSquareIcon, TrashIcon, CheckCircleIcon, ExclamationTriangleIcon, XMarkIcon, 
    ContactsIcon, CalendarDaysIcon, WhatsappIcon, WalletIcon, ArrowRightIcon, ClockIcon,
    ChevronDownIcon, ChevronUpIcon, ArrowDownIcon, ArrowUpIcon
} from './icons';
import { logActivity } from '../lib/logger';

const formatCurrency = (amount: number) => { 
    return new Intl.NumberFormat('ar-LY', { style: 'currency', currency: 'LYD', minimumFractionDigits: 0 }).format(amount).replace('LYD', 'د.ل'); 
};

const Modal: React.FC<{ children: React.ReactNode; title: string; onClose: () => void; }> = ({ children, title, onClose }) => ( 
    <div className="fixed inset-0 z-[60] bg-black/70 backdrop-blur-md flex items-center justify-center p-4 animate-fade-in"> 
        <div className="glass-card bg-slate-900 rounded-[2.5rem] p-6 w-full max-w-md border border-white/10 shadow-2xl animate-slide-up"> 
            <div className="flex justify-between items-center mb-6"> 
                <h3 className="text-xl font-bold text-white">{title}</h3> 
                <button onClick={onClose} className="p-2 rounded-full bg-slate-800 hover:bg-slate-700 transition-colors"><XMarkIcon className="w-5 h-5 text-slate-400" /></button> 
            </div> 
            {children} 
        </div> 
    </div> 
);

const PartialPaymentModal: React.FC<{ debt: Debt, accounts: Account[], onSuccess: () => void, onCancel: () => void }> = ({ debt, accounts, onSuccess, onCancel }) => {
    const [amount, setAmount] = useState('');
    const [accId, setAccId] = useState(accounts[0]?.id || '');
    const [isSaving, setIsSaving] = useState(false);
    const toast = useToast();

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        const payAmount = Number(amount);
        if (payAmount <= 0 || payAmount > debt.amount) return toast.error('مبلغ غير صحيح');

        setIsSaving(true);
        try {
            // 1. Record payment (Installment)
            await supabase.from('debt_payments').insert({
                debt_id: debt.id, amount: payAmount, account_id: accId, payment_date: new Date().toISOString()
            });

            // 2. Update Account
            const { data: acc } = await supabase.from('accounts').select('balance').eq('id', accId).single();
            if (acc) {
                const sign = debt.type === 'on_you' ? -1 : 1;
                await supabase.from('accounts').update({ balance: acc.balance + (payAmount * sign) }).eq('id', accId);
            }

            // 3. Update Debt remaining amount
            const newRemaining = debt.amount - payAmount;
            const isFullyPaid = newRemaining <= 0;
            await supabase.from('debts').update({ 
                amount: Math.max(0, newRemaining), 
                paid: isFullyPaid, 
                paid_at: isFullyPaid ? new Date().toISOString() : null 
            }).eq('id', debt.id);

            // 4. Transaction log
            await supabase.from('transactions').insert({
                account_id: accId,
                amount: payAmount,
                type: debt.type === 'on_you' ? 'expense' : 'income',
                notes: `قسط من دين: ${debt.description || 'بدون وصف'} (لـ ${debt.contacts?.name})`,
                date: new Date().toISOString()
            });

            logActivity(`تسجيل قسط بقيمة ${formatCurrency(payAmount)} لـ ${debt.contacts?.name}`);
            onSuccess();
        } catch (err) {
            toast.error('حدث خطأ أثناء المعالجة');
        } finally {
            setIsSaving(false);
        }
    };

    return (
        <form onSubmit={handleSubmit} className="space-y-6">
            <div className="text-center bg-slate-800/40 p-6 rounded-3xl border border-white/5">
                <p className="text-[10px] text-slate-500 font-black mb-2 uppercase tracking-widest">مبلغ القسط الحالي</p>
                <div className="flex items-center justify-center gap-2">
                    <input type="number" step="0.01" value={amount} onChange={e => setAmount(e.target.value)} required autoFocus placeholder="0.00" className="w-full bg-transparent text-center text-5xl font-black text-cyan-400 focus:outline-none" />
                    <span className="text-xl font-bold text-cyan-600">د.ل</span>
                </div>
                <p className="text-[10px] text-slate-600 font-bold mt-4">المتبقي الكلي من الدين: {formatCurrency(debt.amount)}</p>
            </div>
            <div>
                <label className="text-xs font-bold text-slate-500 block mb-2 px-1">الحساب المستخدم للدفع</label>
                <select value={accId} onChange={e => setAccId(e.target.value)} required className="w-full bg-slate-800 border border-slate-700 rounded-xl p-4 text-white focus:outline-none">
                    {accounts.map(a => <option key={a.id} value={a.id}>{a.name} ({formatCurrency(a.balance)})</option>)}
                </select>
            </div>
            <button type="submit" disabled={isSaving || !amount} className="w-full py-4 bg-cyan-600 text-white rounded-2xl font-black text-lg shadow-xl active:scale-95 transition-all flex items-center justify-center gap-3">
                {isSaving ? <div className="w-6 h-6 border-4 border-white/30 border-t-white rounded-full animate-spin"></div> : <><CheckCircleIcon className="w-6 h-6" /> تأكيد دفع القسط</>}
            </button>
        </form>
    );
};

const DebtItem: React.FC<{ debt: Debt, onPartialPay: (d: Debt) => void, onSelectContact: (id: string) => void }> = ({ debt, onPartialPay, onSelectContact }) => {
    const [showHistory, setShowHistory] = useState(false);
    const isForYou = debt.type === 'for_you';

    // Calculate progress: We need original amount. For simplicity, we calculate (Sum of payments + current amount) as total.
    const paymentsSum = debt.payments?.reduce((s, p) => s + p.amount, 0) || 0;
    const totalOriginal = paymentsSum + debt.amount;
    const progress = totalOriginal > 0 ? (paymentsSum / totalOriginal) * 100 : 0;

    const handleWhatsApp = (e: React.MouseEvent) => {
        e.stopPropagation();
        if (!debt.contacts?.phone) return;
        const msg = `مرحباً ${debt.contacts.name}، تذكير ودي بخصوص المتبقي من الدين: ${formatCurrency(debt.amount)}. شكراً لك.`;
        window.open(`https://wa.me/${debt.contacts.phone.replace(/\D/g,'')}?text=${encodeURIComponent(msg)}`, '_blank');
    };

    return (
        <div className={`glass-card p-5 rounded-[2rem] border border-white/5 transition-all ${debt.paid ? 'opacity-50' : ''}`}>
            <div className="flex justify-between items-start mb-4">
                <div className="flex items-center gap-3">
                    <button onClick={() => debt.contact_id && onSelectContact(debt.contact_id)} className="w-12 h-12 rounded-2xl bg-slate-800 flex items-center justify-center text-white border border-white/5 hover:bg-slate-700 transition-colors">
                        <ContactsIcon className="w-6 h-6" />
                    </button>
                    <div>
                        <h4 className="font-bold text-white text-base">{debt.contacts?.name || 'غير معروف'}</h4>
                        <div className="flex items-center gap-2">
                             <span className={`text-[9px] font-black px-2 py-0.5 rounded-full ${isForYou ? 'bg-emerald-500/10 text-emerald-500' : 'bg-rose-500/10 text-rose-500'}`}>
                                {isForYou ? 'دين لك' : 'دين عليك'}
                            </span>
                            {debt.due_date && <span className="text-[9px] text-slate-500 font-bold flex items-center gap-1"><ClockIcon className="w-3 h-3"/> {new Date(debt.due_date).toLocaleDateString('ar-LY')}</span>}
                        </div>
                    </div>
