                    {[1, 2, 3].map(i => <div key={i} className="h-48 bg-white/5 rounded-[2.5rem] animate-pulse"></div>)}
                </div>
            ) : (
                <div className="space-y-4">
                    <div className="flex justify-between items-center px-2">
                        <h3 className="text-xs font-black text-slate-500 uppercase tracking-widest flex items-center gap-2">
                            <ScaleIcon className="w-4 h-4" /> القائمة الجارية
                        </h3>
                        <div className="flex bg-slate-900 rounded-lg p-1 border border-white/5">
                            <button onClick={() => fetchData()} className="p-1.5 hover:text-cyan-400 transition-colors"><ClockIcon className="w-4 h-4"/></button>
                        </div>
                    </div>

                    {debts.filter(d => d.type === activeTab).length === 0 ? (
                        <div className="py-24 text-center glass-card rounded-[3rem] border-2 border-dashed border-slate-800 bg-slate-900/20">
                            <div className="w-20 h-20 bg-slate-800/50 rounded-full flex items-center justify-center mx-auto mb-6">
                                <CheckCircleIcon className="w-10 h-10 text-slate-700" />
                            </div>
                            <p className="text-slate-500 font-bold text-lg">كل شيء تمام! لا توجد سجلات هنا حالياً.</p>
                        </div>
                    ) : (
                        debts.filter(d => d.type === activeTab).map(debt => (
                            <DebtItemCard 
                                key={debt.id} 
                                debt={debt} 
                                onPay={(d, type) => setPaymentAction({ debt: d, type })} 
                                onSelectContact={onSelectContact}
                                onDelete={setDebtToDelete}
                            />
                        ))
                    )}
                </div>
            )}

            {/* Modals & Dialogs */}
            {paymentAction && (
                <Modal 
                    title={paymentAction.type === 'full' ? 'تسوية الدين بالكامل' : 'تسجيل قسط جديد'} 
                    onClose={() => setPaymentAction(null)}
                >
                    <PaymentModal 
                        debt={paymentAction.debt} 
                        accounts={accounts} 
                        type={paymentAction.type}
                        onSuccess={() => { setPaymentAction(null); handleDatabaseChange(); fetchData(); }} 
                        onCancel={() => setPaymentAction(null)} 
                    />
                </Modal>
            )}

            <ConfirmDialog 
                isOpen={!!debtToDelete}
                title="حذف سجل الدين"
                message="سيتم إزالة هذا الدين تماماً من السجلات، ولن يتم عكس العمليات المالية السابقة المرتبطة به. هل أنت متأكد؟"
                confirmText="نعم، حذف نهائياً"
                onConfirm={handleDeleteDebt}
                onCancel={() => setDebtToDelete(null)}
            />
        </div>
    );
};

export default DebtsPage;

import React, { useState, useEffect, useMemo } from 'react';
import { supabase } from '../lib/supabase';
import { Debt, Contact, Account, DebtPayment } from '../types';
import { useToast } from './Toast';
import ConfirmDialog from './ConfirmDialog';
import { 
    PlusIcon, PencilSquareIcon, TrashIcon, CheckCircleIcon, ExclamationTriangleIcon, XMarkIcon, 
    ContactsIcon, CalendarDaysIcon, WhatsappIcon, WalletIcon, ArrowRightIcon, ClockIcon,
    ChevronDownIcon, ChevronUpIcon, ArrowDownIcon, ArrowUpIcon, ScaleIcon, SparklesIcon
} from './icons';
import { logActivity } from '../lib/logger';

const formatCurrency = (amount: number) => { 
    return new Intl.NumberFormat('ar-LY', { style: 'currency', currency: 'LYD', minimumFractionDigits: 0 }).format(amount).replace('LYD', 'د.ل'); 
};

const Modal: React.FC<{ children: React.ReactNode; title: string; onClose: () => void; }> = ({ children, title, onClose }) => ( 
    <div className="fixed inset-0 z-[60] bg-black/70 backdrop-blur-md flex items-center justify-center p-4 animate-fade-in pt-safe pb-safe"> 
        <div className="glass-card bg-slate-900 rounded-[2.5rem] p-6 w-full max-w-md border border-white/10 shadow-2xl animate-slide-up overflow-hidden relative"> 
            <div className="absolute top-0 right-0 w-32 h-32 bg-cyan-500/10 rounded-full blur-[60px] pointer-events-none"></div>
            <div className="flex justify-between items-center mb-6 relative z-10"> 
                <h3 className="text-xl font-bold text-white">{title}</h3> 
                <button onClick={onClose} className="p-2 rounded-full bg-slate-800 hover:bg-slate-700 transition-colors"><XMarkIcon className="w-5 h-5 text-slate-400" /></button> 
            </div> 
            <div className="relative z-10">{children}</div>
        </div> 
    </div> 
);

const PaymentModal: React.FC<{ 
    debt: Debt, 
    accounts: Account[], 
    mode: 'installment' | 'full',
    onSuccess: () => void, 
    onCancel: () => void 
}> = ({ debt, accounts, mode, onSuccess, onCancel }) => {
    const [amount, setAmount] = useState(mode === 'full' ? debt.amount.toString() : '');
    const [months, setMonths] = useState('1');
    const [accId, setAccId] = useState(accounts[0]?.id || '');
    const [isSaving, setIsSaving] = useState(false);
    const [payMethod, setPayMethod] = useState<'manual' | 'plan'>(mode === 'full' ? 'manual' : 'plan');
    const toast = useToast();

    // Calculate plan
    const calculatedInstallment = useMemo(() => {
        const m = parseInt(months) || 1;
        return (debt.amount / m);
    }, [debt.amount, months]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        const payAmount = payMethod === 'plan' ? calculatedInstallment : Number(amount);

        if (payAmount <= 0 || payAmount > debt.amount + 0.01) return toast.error('مبلغ غير صحيح');

        setIsSaving(true);
        try {
            await supabase.from('debt_payments').insert({
                debt_id: debt.id, amount: payAmount, account_id: accId, payment_date: new Date().toISOString()
            });

            const { data: acc } = await supabase.from('accounts').select('balance').eq('id', accId).single();
            if (acc) {
                const sign = debt.type === 'on_you' ? -1 : 1;
                await supabase.from('accounts').update({ balance: acc.balance + (payAmount * sign) }).eq('id', accId);
            }

            const newRemaining = debt.amount - payAmount;
            const isFullyPaid = newRemaining <= 0.05; // Precision tolerance
            await supabase.from('debts').update({ 
                amount: Math.max(0, newRemaining), 
                paid: isFullyPaid, 
                paid_at: isFullyPaid ? new Date().toISOString() : null 
            }).eq('id', debt.id);

            await supabase.from('transactions').insert({
                account_id: accId,
                amount: payAmount,
                type: debt.type === 'on_you' ? 'expense' : 'income',
                notes: `دفعة (${mode === 'full' ? 'كاملة' : 'قسط'}) لدين: ${debt.description || 'بدون وصف'}`,
                date: new Date().toISOString()
            });

            logActivity(`تسجيل دفعة بقيمة ${formatCurrency(payAmount)} لـ ${debt.contacts?.name}`);
            onSuccess();
        } catch (err) {
            toast.error('حدث خطأ أثناء المعالجة');
        } finally {
            setIsSaving(false);
        }
    };

    return (
        <form onSubmit={handleSubmit} className="space-y-6">
            {mode === 'installment' && (
                <div className="flex bg-slate-800 p-1 rounded-2xl mb-4 shadow-inner">
                    <button type="button" onClick={() => setPayMethod('plan')} className={`flex-1 py-2.5 rounded-xl text-xs font-bold transition-all ${payMethod === 'plan' ? 'bg-cyan-600 text-white shadow-lg' : 'text-slate-500'}`}>خطة أشهر</button>
                    <button type="button" onClick={() => setPayMethod('manual')} className={`flex-1 py-2.5 rounded-xl text-xs font-bold transition-all ${payMethod === 'manual' ? 'bg-cyan-600 text-white shadow-lg' : 'text-slate-500'}`}>مبلغ يدوي</button>
                </div>
            )}

            <div className="text-center bg-slate-800/40 p-6 rounded-3xl border border-white/5 relative overflow-hidden">
                <div className="absolute top-0 left-0 w-full h-1 bg-cyan-500/20"></div>
                <p className="text-[10px] text-slate-500 font-black mb-2 uppercase tracking-widest">
                    {payMethod === 'plan' ? 'القسط الشهري المقترح' : 'المبلغ المراد دفعه الآن'}
                </p>

                {payMethod === 'plan' ? (
                    <div className="space-y-4">
                        <p className="text-4xl font-black text-cyan-400">{formatCurrency(calculatedInstallment)}</p>
                        <div className="flex flex-col gap-2">
                             <label className="text-[10px] text-slate-500 font-bold">تحديد مدة التقسيط (أشهر)</label>
                             <div className="flex items-center justify-center gap-4">
                                <button type="button" onClick={() => setMonths(Math.max(1, parseInt(months)-1).toString())} className="w-10 h-10 rounded-full bg-slate-700 text-white flex items-center justify-center font-bold">-</button>
                                <span className="text-2xl font-black text-white w-12">{months}</span>
                                <button type="button" onClick={() => setMonths((parseInt(months)+1).toString())} className="w-10 h-10 rounded-full bg-slate-700 text-white flex items-center justify-center font-bold">+</button>
                             </div>
                        </div>
                    </div>
                ) : (
                    <div className="flex items-center justify-center gap-2">
                        <input 
                            type="number" 
                            step="0.01" 
                            value={amount} 
                            onChange={e => setAmount(e.target.value)} 
                            readOnly={mode === 'full'}
                            required 
                            autoFocus 
                            className="w-full bg-transparent text-center text-5xl font-black text-cyan-400 focus:outline-none" 
                        />
                        <span className="text-xl font-bold text-cyan-600">د.ل</span>
                    </div>
                )}
            </div>

            <div className="space-y-4">
                <div>
                    <label className="text-[10px] font-black text-slate-500 uppercase px-1 mb-2 block">حساب العملية</label>
                    <select value={accId} onChange={e => setAccId(e.target.value)} required className="w-full bg-slate-800 border border-slate-700 rounded-xl p-4 text-white focus:outline-none">
                        {accounts.map(a => <option key={a.id} value={a.id}>{a.name} ({formatCurrency(a.balance)})</option>)}
                    </select>
                </div>
            </div>

            <button type="submit" disabled={isSaving} className={`w-full py-4 rounded-2xl font-black text-lg shadow-xl active:scale-95 transition-all flex items-center justify-center gap-3 ${mode === 'full' ? 'bg-emerald-600' : 'bg-cyan-600'} text-white`}>
                {isSaving ? <div className="w-6 h-6 border-4 border-white/30 border-t-white rounded-full animate-spin"></div> : <><CheckCircleIcon className="w-6 h-6" /> {mode === 'full' ? 'إغلاق الدين بالكامل' : 'تأكيد دفع القسط'}</>}
            </button>
        </form>
    );
};

const DebtCard: React.FC<{ 
    debt: Debt, 
    onAction: (d: Debt, mode: 'installment' | 'full') => void, 
    onSelectContact: (id: string) => void,
    onDelete: (d: Debt) => void
}> = ({ debt, onAction, onSelectContact, onDelete }) => {
    const [showHistory, setShowHistory] = useState(false);
    const isForYou = debt.type === 'for_you';

    const paymentsSum = debt.payments?.reduce((s, p) => s + p.amount, 0) || 0;
    const totalOriginal = paymentsSum + debt.amount;
    const progress = totalOriginal > 0 ? (paymentsSum / totalOriginal) * 100 : 0;

    const handleWhatsAppReminder = (e: React.MouseEvent) => {
        e.stopPropagation();
        if (!debt.contacts?.phone) return;
        const msg = `مرحباً ${debt.contacts.name}، أتمنى أن تكون بخير. تذكير ودي بخصوص المتبقي من الدين: ${formatCurrency(debt.amount)}. شكراً لك.`;
        window.open(`https://wa.me/${debt.contacts.phone.replace(/\D/g,'')}?text=${encodeURIComponent(msg)}`, '_blank');
    };

    return (
        <div className={`glass-card p-5 rounded-[2.5rem] border border-white/5 transition-all relative overflow-hidden group ${debt.paid ? 'opacity-40 grayscale' : 'hover:border-white/10 shadow-lg'}`}>
            {/* Design accents */}
            <div className={`absolute top-0 right-0 w-24 h-24 blur-3xl opacity-5 pointer-events-none rounded-full ${isForYou ? 'bg-emerald-500' : 'bg-rose-500'}`}></div>

            <div className="flex justify-between items-start mb-5 relative z-10">
                <div className="flex items-center gap-4">
                    <button 
                        onClick={() => debt.contact_id && onSelectContact(debt.contact_id)}
                        className={`w-14 h-14 rounded-2xl flex items-center justify-center text-white border border-white/10 transition-all active:scale-90 shadow-inner ${isForYou ? 'bg-emerald-500/20 text-emerald-400' : 'bg-rose-500/20 text-rose-400'}`}
                    >
                        <ContactsIcon className="w-7 h-7" />
                    </button>
                    <div>
                        <h4 className="font-black text-white text-lg leading-none mb-1">{debt.contacts?.name || 'غير معروف'}</h4>
                        <div className="flex items-center gap-2">
                             <span className={`text-[9px] font-black px-2 py-0.5 rounded-full uppercase tracking-tighter ${isForYou ? 'bg-emerald-500/20 text-emerald-400' : 'bg-rose-500/20 text-rose-400'}`}>
                                {isForYou ? 'لك (تحصيل)' : 'عليك (سداد)'}
                            </span>
                            {debt.due_date && <span className="text-[9px] text-slate-500 font-bold flex items-center gap-1"><ClockIcon className="w-3 h-3"/> {new Date(debt.due_date).toLocaleDateString('ar-LY')}</span>}
                        </div>
                    </div>
                </div>
                <div className="text-left">
                    <p className={`text-2xl font-black tabular-nums tracking-tighter ${isForYou ? 'text-emerald-400' : 'text-rose-400'}`}>
                        {formatCurrency(debt.amount)}
                    </p>
                    <p className="text-[10px] text-slate-500 font-bold max-w-[100px] truncate">{debt.description || 'بدون وصف'}</p>
                </div>
            </div>

            {/* Visual Progress Section */}
            {!debt.paid && (
                <div className="mb-6 space-y-2">
                    <div className="flex justify-between text-[10px] font-black text-slate-500 uppercase tracking-widest px-1">
                        <span>التم السداد: {progress.toFixed(0)}%</span>
                        <span>الإجمالي: {formatCurrency(totalOriginal)}</span>
                    </div>
                    <div className="h-2 bg-slate-800 rounded-full overflow-hidden p-0 border border-white/5 shadow-inner">
                        <div 
                            className={`h-full rounded-full transition-all duration-1000 ${isForYou ? 'bg-emerald-500' : 'bg-rose-500'}`} 
                            style={{ width: `${progress}%` }}
                        ></div>
                    </div>
                </div>
            )}

            {/* Smart Action Buttons */}
            <div className="flex gap-2 pt-2 border-t border-white/5 relative z-10">
                {!debt.paid ? (
                    <>
                        <button onClick={() => onAction(debt, 'installment')} className="flex-[1.5] py-3 bg-white/5 hover:bg-white/10 text-white rounded-2xl text-[11px] font-black transition-all border border-white/5 flex items-center justify-center gap-2">
                            <ScaleIcon className="w-4 h-4 text-cyan-400" /> تقسيط
                        </button>
                        <button onClick={() => onAction(debt, 'full')} className="flex-1 py-3 bg-emerald-600/10 hover:bg-emerald-600/20 text-emerald-400 rounded-2xl text-[11px] font-black transition-all border border-emerald-500/20">
                            إغلاق كامل
                        </button>
                        {isForYou && debt.contacts?.phone && (
                            <button onClick={handleWhatsAppReminder} className="p-3 bg-emerald-600 text-white rounded-2xl shadow-lg shadow-emerald-900/30 active:scale-95 transition-transform" title="تذكير واتساب">
                                <WhatsappIcon className="w-5 h-5" />
                            </button>
                        )}
                    </>
                ) : (
                    <div className="w-full py-3 bg-emerald-500/5 rounded-2xl text-center text-xs font-black text-emerald-500/50 flex items-center justify-center gap-3">
                        <CheckCircleIcon className="w-5 h-5" /> تم التسوية بالكامل بنجاح
                    </div>
                )}

                <button onClick={() => setShowHistory(!showHistory)} className={`p-3 rounded-2xl transition-all ${showHistory ? 'bg-white/10 text-white' : 'bg-white/5 text-slate-500 hover:text-white'}`}>
                    {showHistory ? <ChevronUpIcon className="w-5 h-5" /> : <ChevronDownIcon className="w-5 h-5" />}
                </button>
            </div>

            {/* Payments History (Installments) */}
            {showHistory && (
                <div className="mt-5 space-y-2 animate-fade-in border-t border-white/5 pt-4">
                    <div className="flex justify-between items-center px-2 mb-3">
                        <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">سجل الدفعات</p>
                        <span className="text-[9px] font-bold text-slate-600">{debt.payments?.length || 0} دفعة</span>
                    </div>
                    {debt.payments && debt.payments.length > 0 ? debt.payments.map(p => (
                        <div key={p.id} className="bg-white/[0.02] p-3 rounded-2xl flex justify-between items-center border border-white/5">
                            <div className="flex items-center gap-3">
                                <div className="w-8 h-8 rounded-xl bg-slate-800 flex items-center justify-center text-slate-500">
                                    <CalendarDaysIcon className="w-4 h-4" />
                                </div>
                                <div>
                                    <p className="text-xs font-bold text-slate-300">{new Date(p.payment_date).toLocaleDateString('ar-LY')}</p>
                                    <p className="text-[9px] text-slate-500">{p.accounts?.name || 'حساب غير معروف'}</p>
                                </div>
                            </div>
                            <span className="text-sm font-black text-cyan-400 tabular-nums">{formatCurrency(p.amount)}</span>
                        </div>
                    )) : (
                        <p className="text-[10px] text-center text-slate-700 py-6 italic border-2 border-dashed border-white/5 rounded-2xl">لا يوجد أقساط مسددة حالياً</p>
                    )}
                    <button onClick={() => onDelete(debt)} className="w-full py-2.5 text-rose-500/30 hover:text-rose-500 text-[10px] font-black transition-colors mt-4">حذف سجل الدين نهائياً</button>
                </div>
            )}
        </div>
    );
};

const DebtsPage: React.FC<{ refreshTrigger: number, handleDatabaseChange: (description?: string) => void, onSelectContact: (contactId: string) => void }> = ({ refreshTrigger, handleDatabaseChange, onSelectContact }) => {
    const [debts, setDebts] = useState<Debt[]>([]);
    const [accounts, setAccounts] = useState<Account[]>([]);
    const [loading, setLoading] = useState(true);
    const [activeTab, setActiveTab] = useState<'on_you' | 'for_you'>('for_you');
    const [actionState, setActionState] = useState<{ debt: Debt, mode: 'installment' | 'full' } | null>(null);
    const [debtToDelete, setDebtToDelete] = useState<Debt | null>(null);
    const toast = useToast();

    const fetchData = async () => {
        setLoading(true);
        const [dRes, aRes] = await Promise.all([
            supabase.from('debts').select('*, contacts(*), accounts(name), payments:debt_payments(*, accounts(name))').order('due_date'),
            supabase.from('accounts').select('*')
        ]);
        setDebts(dRes.data as unknown as Debt[] || []);
        setAccounts(aRes.data || []);
        setLoading(false);
    };

    useEffect(() => { fetchData(); }, [refreshTrigger]);

    const stats = useMemo(() => {
        const active = debts.filter(d => !d.paid);
        return {
            forYou: active.filter(d => d.type === 'for_you').reduce((s, d) => s + d.amount, 0),
            onYou: active.filter(d => d.type === 'on_you').reduce((s, d) => s + d.amount, 0)
        };
    }, [debts]);

    const handleDeleteDebt = async () => {
        if (!debtToDelete) return;
        const { error } = await supabase.from('debts').delete().eq('id', debtToDelete.id);
        if (!error) {
            toast.success('تم حذف سجل الدين بنجاح');
            handleDatabaseChange();
            fetchData();
        }
        setDebtToDelete(null);
    };

    return (
        <div className="space-y-8 pb-32 max-w-4xl mx-auto px-1">
            {/* Header Summary Totals */}
            <div className="grid grid-cols-2 gap-4">
                <button onClick={() => setActiveTab('for_you')} className={`p-6 rounded-[2.5rem] border transition-all relative overflow-hidden group ${activeTab === 'for_you' ? 'bg-emerald-500/10 border-emerald-500/50 shadow-xl' : 'bg-slate-900/50 border-white/5 opacity-60'}`}>
                    <div className="absolute top-0 right-0 w-24 h-24 bg-emerald-500/5 blur-3xl rounded-full"></div>
                    <p className="text-[11px] font-black text-slate-500 uppercase mb-2 flex items-center gap-2">
                        <ArrowDownIcon className="w-4 h-4 text-emerald-500" /> ديون لك (تحصيل)
                    </p>
                    <p className="text-3xl font-black text-white tabular-nums tracking-tighter leading-none">{formatCurrency(stats.forYou)}</p>
                </button>
                <button onClick={() => setActiveTab('on_you')} className={`p-6 rounded-[2.5rem] border transition-all relative overflow-hidden group ${activeTab === 'on_you' ? 'bg-rose-500/10 border-rose-500/50 shadow-xl' : 'bg-slate-900/50 border-white/5 opacity-60'}`}>
                    <div className="absolute top-0 right-0 w-24 h-24 bg-rose-500/5 blur-3xl rounded-full"></div>
                    <p className="text-[11px] font-black text-slate-500 uppercase mb-2 flex items-center gap-2">
                        <ArrowUpIcon className="w-4 h-4 text-rose-500" /> ديون عليك (سداد)
                    </p>
                    <p className="text-3xl font-black text-white tabular-nums tracking-tighter leading-none">{formatCurrency(stats.onYou)}</p>
                </button>
            </div>

            {/* Section Header */}
            <div className="flex justify-between items-center px-3">
                 <h3 className="text-xs font-black text-slate-500 uppercase tracking-widest flex items-center gap-2">
                    <ClockIcon className="w-4 h-4" /> السجلات النشطة حالياً
                </h3>
                <div className="bg-slate-900 rounded-xl p-1 border border-white/5 flex">
                    <button onClick={() => fetchData()} className="p-2 text-slate-400 hover:text-cyan-400 transition-colors"><SparklesIcon className="w-4 h-4"/></button>
                </div>
            </div>

            {/* Debt List */}
            {loading ? (
                <div className="space-y-4">
                    {[1, 2, 3].map(i => <div key={i} className="h-44 bg-white/5 rounded-[2.5rem] animate-pulse border border-white/5"></div>)}
                </div>
            ) : (
                <div className="space-y-5">
                    {debts.filter(d => d.type === activeTab).length === 0 ? (
                        <div className="py-24 text-center glass-card rounded-[3rem] border-2 border-dashed border-slate-800 bg-slate-900/20">
                            <div className="w-20 h-20 bg-slate-800/50 rounded-full flex items-center justify-center mx-auto mb-6">
                                <CheckCircleIcon className="w-10 h-10 text-slate-700 opacity-30" />
                            </div>
                            <p className="text-slate-600 font-bold text-lg">لا توجد ديون مسجلة في هذا القسم</p>
                        </div>
                    ) : (
                        debts.filter(d => d.type === activeTab).map(debt => (
                            <DebtCard 
                                key={debt.id} 
                                debt={debt} 
                                onAction={(d, mode) => setActionState({ debt: d, mode })} 
                                onSelectContact={onSelectContact}
                                onDelete={setDebtToDelete}
                            />
                        ))
                    )}
                </div>
            )}

            {/* Modals & Dialogs */}
            {actionState && (
                <Modal 
                    title={actionState.mode === 'full' ? 'تسوية الدين بالكامل' : 'مساعد التقسيط الذكي'} 
                    onClose={() => setActionState(null)}
                >
                    <PaymentModal 
                        debt={actionState.debt} 
                        accounts={accounts} 
                        mode={actionState.mode}
                        onSuccess={() => { setActionState(null); handleDatabaseChange(); fetchData(); }} 
                        onCancel={() => setActionState(null)} 
                    />
                </Modal>
            )}

            <ConfirmDialog 
