                    <div className="w-full py-2.5 bg-emerald-500/10 rounded-2xl text-center text-xs font-black text-emerald-500 flex items-center justify-center gap-2">
                        <CheckCircleIcon className="w-5 h-5" /> تم التسديد بالكامل
